import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { prisma } from "@/lib/db";
import { ingestLatest } from "@/lib/hn/ingest";
import { enrichJobs } from "@/lib/hn/enrich-jobs";
import { formatMonth, formatDate } from "@/lib/format";

export const dynamic = "force-dynamic";

export default async function AdminIngestPage({
  searchParams,
}: {
  searchParams: { done?: string; n?: string; msg?: string; err?: string };
}) {
  const [threads, pendingEnrichment, enriched, missed, failed] = await Promise.all([
    prisma.thread.findMany({ orderBy: { month: "desc" } }),
    prisma.job.count({ where: { enrichmentStatus: "pending" } }),
    prisma.job.count({ where: { enrichmentStatus: "enriched" } }),
    prisma.job.count({ where: { enrichmentStatus: "missed" } }),
    prisma.job.count({ where: { enrichmentStatus: "failed" } }),
  ]);

  async function runIngest(formData: FormData) {
    "use server";
    const count = Number(formData.get("count") ?? 1) || 1;
    let target: string;
    try {
      const results = await ingestLatest(count);
      const total = results.reduce((s, r) => s + r.total, 0);
      revalidatePath("/admin/ingest");
      revalidatePath("/");
      target = `/admin/ingest?done=1&n=${total}`;
    } catch (e) {
      target = `/admin/ingest?err=${encodeURIComponent(String(e).slice(0, 120))}`;
    }
    // redirect() throws NEXT_REDIRECT — must be outside the try/catch above.
    redirect(target);
  }

  async function runEnrichment(formData: FormData) {
    "use server";
    const limit = Number(formData.get("limit") ?? 50) || 50;
    const retry = formData.get("retry") === "1";
    let target: string;
    try {
      const result = await enrichJobs({ limit, retry });
      revalidatePath("/admin/ingest");
      revalidatePath("/");
      target = `/admin/ingest?msg=${encodeURIComponent(
        `enriched ${result.enriched}; missed ${result.missed}; failed ${result.failed}; scanned ${result.scanned}`
      )}`;
    } catch (e) {
      target = `/admin/ingest?err=${encodeURIComponent(String(e).slice(0, 120))}`;
    }
    redirect(target);
  }

  return (
    <div>
      <h2 className="section">Ingest from Hacker News</h2>
      <p className="small muted" style={{ maxWidth: 600 }}>
        Pulls the latest &ldquo;Who is hiring?&rdquo; thread(s) from the HN
        Algolia API and upserts every top-level posting. Idempotent &mdash;
        re-running refreshes the parse without duplicating rows or touching the
        stored raw text. Hidden flags are preserved.
      </p>

      {searchParams.done && (
        <p className="small" style={{ color: "var(--success)" }}>
          Ingest complete. {searchParams.n ?? "?"} postings now in the latest set.
        </p>
      )}
      {searchParams.msg && (
        <p className="small" style={{ color: "var(--success)" }}>
          {searchParams.msg}
        </p>
      )}
      {searchParams.err && (
        <p className="small" style={{ color: "var(--error)" }}>
          Ingest failed: {searchParams.err}
        </p>
      )}

      <form className="submit-form" action={runIngest}>
        <label htmlFor="count">How many recent months to pull</label>
        <select id="count" name="count" defaultValue="1">
          <option value="1">Latest month only</option>
          <option value="3">Last 3 months</option>
          <option value="6">Last 6 months</option>
        </select>
        <button type="submit">Run ingest now</button>
      </form>

      <h2 className="section">Careers-page enrichment</h2>
      <p className="small muted" style={{ maxWidth: 600 }}>
        Probes common careers URLs on rows that have a company website but no
        parsed apply link. Runs in bounded batches; existing apply links and raw
        HN snapshots are left alone.
      </p>
      <table className="fact-table">
        <tbody>
          <tr><th>Pending</th><td>{pendingEnrichment}</td></tr>
          <tr><th>Enriched</th><td>{enriched}</td></tr>
          <tr><th>Missed</th><td>{missed}</td></tr>
          <tr><th>Failed</th><td>{failed}</td></tr>
        </tbody>
      </table>
      <form className="submit-form" action={runEnrichment}>
        <label htmlFor="limit">How many postings to probe</label>
        <select id="limit" name="limit" defaultValue="50">
          <option value="25">25 postings</option>
          <option value="50">50 postings</option>
          <option value="100">100 postings</option>
        </select>
        <label>
          <input type="checkbox" name="retry" value="1" /> Retry missed/failed rows
        </label>
        <button type="submit">Run enrichment</button>
      </form>

      <h2 className="section">Indexed threads</h2>
      <table className="data">
        <thead>
          <tr>
            <th>Month</th>
            <th className="num">Postings</th>
            <th>HN thread</th>
            <th>Last ingested</th>
          </tr>
        </thead>
        <tbody>
          {threads.map((t) => (
            <tr key={t.id}>
              <td>{formatMonth(t.month)}</td>
              <td className="num">{t.jobCount}</td>
              <td>
                <a href={`https://news.ycombinator.com/item?id=${t.hnId}`} target="_blank" rel="noopener noreferrer">
                  {t.hnId} ↗
                </a>
              </td>
              <td>{t.lastIngestedAt ? formatDate(t.lastIngestedAt) : <span className="muted-2">—</span>}</td>
            </tr>
          ))}
          {threads.length === 0 && (
            <tr><td colSpan={4} className="muted">No threads yet. Run an ingest above.</td></tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

