import Link from "next/link";
import { revalidatePath } from "next/cache";
import { prisma } from "@/lib/db";
import { snippet } from "@/lib/format";

export const dynamic = "force-dynamic";

async function setHidden(id: number, hidden: boolean, reason?: string) {
  "use server";
  await prisma.job.update({
    where: { id },
    data: { hidden, hiddenReason: hidden ? reason ?? "hidden by admin" : null },
  });
  revalidatePath("/admin/jobs");
  revalidatePath("/");
}

export default async function AdminJobsPage({
  searchParams,
}: {
  searchParams: { q?: string; show?: string };
}) {
  const q = (searchParams.q ?? "").trim();
  const showHidden = searchParams.show === "hidden";

  const jobs = await prisma.job.findMany({
    where: {
      ...(showHidden ? { hidden: true } : {}),
      ...(q
        ? {
            OR: [
              { company: { contains: q } },
              { role: { contains: q } },
              { rawText: { contains: q } },
              { author: { contains: q } },
            ],
          }
        : {}),
    },
    include: { thread: { select: { month: true } } },
    orderBy: { postedAt: "desc" },
    take: 300,
  });

  return (
    <div>
      <h2 className="section">Jobs</h2>
      <form className="search-form" action="/admin/jobs" method="get" style={{ maxWidth: 420 }}>
        {showHidden && <input type="hidden" name="show" value="hidden" />}
        <input className="searchbox" type="text" name="q" placeholder="Search company / role / text…" defaultValue={q} />
      </form>
      <p className="small muted">
        {showHidden ? (
          <Link href="/admin/jobs">← Back to visible postings</Link>
        ) : (
          <Link href="/admin/jobs?show=hidden">View hidden postings</Link>
        )}
        {"  ·  "}
        {jobs.length} shown (max 300)
      </p>

      <table className="data">
        <thead>
          <tr>
            <th>Month</th>
            <th>Company</th>
