import Link from "next/link";
import { redirect } from "next/navigation";
import { adminConfigured, isAdmin } from "@/lib/auth";

// Auth gate. Any unauthenticated request to /admin/* bounces to /login.
export const dynamic = "force-dynamic";

export default async function AdminLayout({ children }: { children: React.ReactNode }) {
  if (!adminConfigured()) {
    return (
      <div>
        <p className="results-info">
          <Link href="/">&larr; Back to site</Link>
        </p>
        <h2 className="section">Admin is not configured</h2>
        <p style={{ maxWidth: 600 }}>
          Set <code>ADMIN_PASSWORD</code> in your <code>.env</code> file
          (minimum 4 characters), restart the dev server, then refresh this page.
        </p>
      </div>
    );
  }

  if (!(await isAdmin())) redirect("/login");

  return (
    <div>
      <nav style={{ marginBottom: 16, fontSize: 12 }}>
        <span className="path-tag">admin</span>
        <Link href="/admin">Dashboard</Link>
        {"  ·  "}
        <Link href="/admin/jobs">Jobs</Link>
        {"  ·  "}
        <Link href="/admin/quality">Quality</Link>
        {"  ·  "}
        <Link href="/admin/taxonomy">Taxonomy</Link>
        {"  ·  "}
        <Link href="/admin/ingest">Ingest</Link>
        {"  ·  "}
        <Link href="/admin/logout" prefetch={false}>Log out</Link>
      </nav>
      {children}
    </div>
  );
}

