import Link from "next/link";
import { prisma } from "@/lib/db";
import { formatMonth, formatDate } from "@/lib/format";
import { qualityBucketCounts } from "@/lib/admin-quality";

export const dynamic = "force-dynamic";

export default async function AdminDashboard() {
  const [jobCount, hiddenCount, threadCount, latestThread] = await Promise.all([
    prisma.job.count({ where: { hidden: false } }),
    prisma.job.count({ where: { hidden: true } }),
    prisma.thread.count(),
    prisma.thread.findFirst({ orderBy: { month: "desc" } }),
  ]);
  const [needsReview, unknownCount] = await Promise.all([
    prisma.job.count({ where: { needsReview: true } }),
    prisma.job.count({ where: { classificationConfidence: "unknown" } }),
  ]);
  const qualityRows = await prisma.job.findMany({
    where: { hidden: false },
    select: {
      parseConfidence: true,
      company: true,
      role: true,
      applyMethod: true,
      applyUrl: true,
      applyEmail: true,
      needsReview: true,
      classificationConfidence: true,
      enrichmentStatus: true,
    },
  });
  const qualityCounts = qualityBucketCounts(qualityRows);

  return (
    <div>
      <h2 className="section">Dashboard</h2>
      <table className="fact-table">
        <tbody>
          <tr><th>Visible postings</th><td>{jobCount}</td></tr>
          <tr><th>Hidden postings</th><td>{hiddenCount}</td></tr>
          <tr><th>Threads indexed</th><td>{threadCount}</td></tr>
          <tr>
            <th>Taxonomy review</th>
            <td>
              <Link href="/admin/taxonomy">{needsReview} need review</Link>
              {unknownCount > 0 && <span className="muted"> · {unknownCount} unknown</span>}
            </td>
          </tr>
          <tr>
            <th>Quality queues</th>
            <td>
              <Link href="/admin/quality?show=weak-parse">{qualityCounts["weak-parse"]} weak parses</Link>
              {" · "}
              <Link href="/admin/quality?show=missing-apply">{qualityCounts["missing-apply"]} missing apply</Link>
              {" · "}
              <Link href="/admin/quality?show=enrichment-attention">{qualityCounts["enrichment-attention"]} enrichment</Link>
            </td>
          </tr>
          <tr>
            <th>Latest thread</th>
            <td>
              {latestThread ? (
                <>
                  {formatMonth(latestThread.month)} · {latestThread.jobCount} postings
                  {latestThread.lastIngestedAt && (
                    <span className="muted"> · ingested {formatDate(latestThread.lastIngestedAt)}</span>
                  )}
                </>
              ) : (
                <span className="muted-2">none yet</span>
              )}
            </td>
          </tr>
        </tbody>
      </table>

      <p className="small muted">
        Pull the newest &ldquo;Who is hiring?&rdquo; thread from{" "}
        <Link href="/admin/ingest">Ingest</Link>, hide spam/recruiter posts
        from <Link href="/admin/jobs">Jobs</Link>, review data gaps in{" "}
        <Link href="/admin/quality">Quality</Link>, or clean role/category
        mappings in <Link href="/admin/taxonomy">Taxonomy</Link>.
      </p>
    </div>
  );
}

