import Link from "next/link";
import { prisma } from "@/lib/db";
import { formatCompanyName, snippet } from "@/lib/format";
import {
  QUALITY_BUCKETS,
  parseQualityBucket,
  qualityBucketCounts,
  qualityBucketLabel,
  rowMatchesQualityBucket,
} from "@/lib/admin-quality";

export const dynamic = "force-dynamic";

type SearchParams = { show?: string; q?: string };

export default async function AdminQualityPage({ searchParams }: { searchParams: SearchParams }) {
  const bucket = parseQualityBucket(searchParams.show);
  const q = (searchParams.q ?? "").trim();

  const statsRows = await prisma.job.findMany({
    where: { hidden: false },
    select: {
      parseConfidence: true,
      company: true,
      role: true,
      applyMethod: true,
      applyUrl: true,
      applyEmail: true,
      needsReview: true,
      classificationConfidence: true,
      enrichmentStatus: true,
    },
  });
  const counts = qualityBucketCounts(statsRows);

  const candidateRows = await prisma.job.findMany({
    where: {
      hidden: false,
      ...(q
        ? {
            OR: [
              { company: { contains: q } },
              { role: { contains: q } },
              { rawText: { contains: q } },
              { reviewReason: { contains: q } },
              { enrichmentNotes: { contains: q } },
            ],
          }
        : {}),
    },
    include: { thread: { select: { month: true } } },
    orderBy: { postedAt: "desc" },
    take: 2000,
  });
  const rows = candidateRows.filter((row) => rowMatchesQualityBucket(row, bucket)).slice(0, 160);

  return (
    <div>
      <h2 className="section">Quality</h2>
      <p className="small muted" style={{ maxWidth: 700 }}>
        Triage derived-data gaps without touching raw HN snapshots. Counts cover
        visible postings only; hiding a post removes it from this queue.
      </p>

      <table className="fact-table">
        <tbody>
          {QUALITY_BUCKETS.map((key) => (
            <tr key={key}>
              <th>{qualityBucketLabel(key)}</th>
              <td>
                <Link href={`/admin/quality?show=${key}`}>{counts[key]}</Link>
                {bucket === key && <span className="muted"> · showing</span>}
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      <form className="search-form" action="/admin/quality" method="get" style={{ maxWidth: 420 }}>
        <input type="hidden" name="show" value={bucket} />
        <input className="searchbox" type="text" name="q" placeholder="Search company / role / notes…" defaultValue={q} />
      </form>
      <p className="small muted">
        Showing {qualityBucketLabel(bucket)?.toLowerCase()} · {rows.length} rows (max 160)
        {"  ·  "}
        <Link href="/admin/taxonomy">Taxonomy review</Link>
        {"  ·  "}
        <Link href="/admin/ingest">Enrichment</Link>
      </p>

      <table className="data">
        <thead>
          <tr>
            <th>Month</th>
            <th>Company</th>
            <th>Role</th>
            <th>Posting</th>
            <th>Parse</th>
            <th>Apply</th>
            <th>Taxonomy</th>
            <th>Enrichment</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((job) => {
            const company = formatCompanyName(job.company);
            return (
              <tr key={job.id}>
                <td className="small">{job.thread.month}</td>
                <td>
                  <Link href={`/job/${job.id}`}>{company ?? "—"}</Link>
                </td>
                <td className="small">{job.role ?? <span className="muted-2">—</span>}</td>
                <td className="small">{snippet(job.rawText, 84)}</td>
                <td className="small">
                  <span className={`conf-${job.parseConfidence}`}>{job.parseConfidence}</span>
                </td>
                <td className="small">
                  {job.applyUrl ? (
                    <a href={job.applyUrl} target="_blank" rel="noopener noreferrer">link ↗</a>
                  ) : job.applyEmail ? (
                    <a href={`mailto:${job.applyEmail}`}>email ↗</a>
                  ) : job.applyMethod === "hn-reply" ? (
                    <a href={job.hnUrl} target="_blank" rel="noopener noreferrer">HN reply ↗</a>
                  ) : (
                    <span className="muted-2">missing</span>
                  )}
                </td>
                <td className="small">
                  {job.needsReview || job.classificationConfidence === "low" || job.classificationConfidence === "unknown" ? (
                    <Link href={`/admin/taxonomy?q=${encodeURIComponent(company ?? job.role ?? "")}`}>
                      {job.classificationConfidence}
                    </Link>
                  ) : (
                    job.classificationConfidence
                  )}
                  {job.reviewReason && <div className="muted-2">{job.reviewReason}</div>}
                </td>
                <td className="small">
                  {job.enrichmentStatus}
                  {job.enrichmentNotes && <div className="muted-2">{job.enrichmentNotes}</div>}
                </td>
              </tr>
            );
          })}
          {rows.length === 0 && (
            <tr><td colSpan={8} className="muted">No rows match this quality bucket.</td></tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

