import Link from "next/link";
import { revalidatePath } from "next/cache";
import { redirect } from "next/navigation";
import { prisma } from "@/lib/db";
import { formatCompanyName, parseJsonArray, snippet } from "@/lib/format";
import { classifyJobs } from "@/lib/hn/classify";
import {
  ROLE_FAMILIES,
  SENIORITY_LEVELS,
  TAXONOMY_VERSION,
  type ClassificationConfidence,
} from "@/lib/hn/taxonomy";

export const dynamic = "force-dynamic";

type SearchParams = { q?: string; show?: string; done?: string; err?: string };

function listInput(value: FormDataEntryValue | null): string[] {
  return String(value ?? "")
    .split(/[,\n]/)
    .map((v) => v.trim())
    .filter(Boolean);
}

function confidenceInput(value: FormDataEntryValue | null): ClassificationConfidence {
  const raw = String(value ?? "medium");
  return raw === "high" || raw === "medium" || raw === "low" || raw === "unknown"
    ? raw
    : "medium";
}

async function reclassifyAll() {
  "use server";
  let target: string;
  try {
    const result = await classifyJobs();
    revalidatePath("/admin/taxonomy");
    revalidatePath("/");
    target = `/admin/taxonomy?done=${encodeURIComponent(`classified ${result.classified}; ${result.needsReview} need review`)}`;
  } catch (e) {
    target = `/admin/taxonomy?err=${encodeURIComponent(String(e).slice(0, 140))}`;
  }
  redirect(target);
}

async function reclassifyReviewQueue() {
  "use server";
  let target: string;
  try {
    const result = await classifyJobs({ reviewOnly: true });
    revalidatePath("/admin/taxonomy");
    revalidatePath("/");
    target = `/admin/taxonomy?done=${encodeURIComponent(`classified ${result.classified}; ${result.needsReview} still need review`)}`;
  } catch (e) {
    target = `/admin/taxonomy?err=${encodeURIComponent(String(e).slice(0, 140))}`;
  }
  redirect(target);
}

async function saveTaxonomy(formData: FormData) {
  "use server";
  const id = Number(formData.get("id"));
  if (!Number.isFinite(id)) return;

  const roleFamilies = listInput(formData.get("roleFamilies")).filter((family) =>
    ROLE_FAMILIES.includes(family as (typeof ROLE_FAMILIES)[number])
  );
  const roleSpecialties = listInput(formData.get("roleSpecialties"));
  const locationRegions = listInput(formData.get("locationRegions"));
  const seniorityRaw = String(formData.get("seniority") ?? "");
  const seniority = SENIORITY_LEVELS.includes(seniorityRaw as (typeof SENIORITY_LEVELS)[number])
    ? seniorityRaw
    : null;
  const needsReview = String(formData.get("needsReview") ?? "0") === "1";
  const reviewReason = String(formData.get("reviewReason") ?? "").trim() || null;

  await prisma.job.update({
    where: { id },
    data: {
      roleFamilies: JSON.stringify(roleFamilies),
      roleSpecialties: JSON.stringify(roleSpecialties),
      seniority,
      locationRegions: JSON.stringify(locationRegions),
      classificationConfidence: confidenceInput(formData.get("classificationConfidence")),
      needsReview,
      reviewReason: needsReview ? reviewReason ?? "admin marked for review" : reviewReason,
      taxonomyVersion: `${TAXONOMY_VERSION}:manual`,
    },
  });
  revalidatePath("/admin/taxonomy");
  revalidatePath("/");
}

async function markReviewed(formData: FormData) {
  "use server";
  const id = Number(formData.get("id"));
  if (!Number.isFinite(id)) return;
  await prisma.job.update({
    where: { id },
    data: {
      needsReview: false,
      reviewReason: null,
      taxonomyVersion: `${TAXONOMY_VERSION}:reviewed`,
    },
  });
  revalidatePath("/admin/taxonomy");
  revalidatePath("/");
}

export default async function AdminTaxonomyPage({ searchParams }: { searchParams: SearchParams }) {
  const q = (searchParams.q ?? "").trim();
  const showAll = searchParams.show === "all";

  const [total, needsReview, high, medium, low, unknown, statsRows] = await Promise.all([
    prisma.job.count(),
    prisma.job.count({ where: { needsReview: true } }),
    prisma.job.count({ where: { classificationConfidence: "high" } }),
    prisma.job.count({ where: { classificationConfidence: "medium" } }),
    prisma.job.count({ where: { classificationConfidence: "low" } }),
    prisma.job.count({ where: { classificationConfidence: "unknown" } }),
    prisma.job.findMany({ select: { roleFamilies: true } }),
  ]);

  const familyCounts = new Map<string, number>();
  for (const row of statsRows) {
    for (const family of parseJsonArray(row.roleFamilies)) {
      familyCounts.set(family, (familyCounts.get(family) ?? 0) + 1);
    }
  }

  const jobs = await prisma.job.findMany({
    where: {
      ...(showAll ? {} : { needsReview: true }),
      ...(q
        ? {
            OR: [
              { company: { contains: q } },
              { role: { contains: q } },
              { rawText: { contains: q } },
              { reviewReason: { contains: q } },
            ],
          }
        : {}),
    },
    include: { thread: { select: { month: true } } },
    orderBy: [{ needsReview: "desc" }, { postedAt: "desc" }],
    take: 120,
  });

  return (
    <div>
      <h2 className="section">Taxonomy</h2>
      <p className="small muted" style={{ maxWidth: 700 }}>
        Role families, specialties, seniority, location regions, and salary
        disclosure are derived from parsed HN posts. Reclassifying never changes
        raw HN snapshots or hidden moderation state.
      </p>

      {searchParams.done && (
        <p className="small" style={{ color: "var(--success)" }}>{searchParams.done}</p>
      )}
      {searchParams.err && (
        <p className="small" style={{ color: "var(--error)" }}>Taxonomy failed: {searchParams.err}</p>
      )}

      <table className="fact-table">
        <tbody>
          <tr><th>Total jobs</th><td>{total}</td></tr>
          <tr><th>Needs review</th><td>{needsReview}</td></tr>
          <tr><th>Confidence</th><td>high {high} · medium {medium} · low {low} · unknown {unknown}</td></tr>
          <tr>
            <th>Top families</th>
            <td className="tags">
              {Array.from(familyCounts.entries())
                .sort((a, b) => b[1] - a[1])
                .slice(0, 8)
                .map(([family, count]) => (
                  <span className="t" key={family}>{family} {count}</span>
                ))}
            </td>
          </tr>
        </tbody>
      </table>

      <div className="admin-actions">
        <form action={reclassifyReviewQueue}>
          <button className="btn-secondary" type="submit">Reclassify review queue</button>
        </form>
        <form action={reclassifyAll}>
          <button className="btn" type="submit">Reclassify all jobs</button>
        </form>
      </div>

      <form className="search-form" action="/admin/taxonomy" method="get" style={{ maxWidth: 420 }}>
        {showAll && <input type="hidden" name="show" value="all" />}
        <input className="searchbox" type="text" name="q" placeholder="Search company / role / reason…" defaultValue={q} />
      </form>
      <p className="small muted">
        {showAll ? (
          <Link href="/admin/taxonomy">Show review queue only</Link>
        ) : (
          <Link href="/admin/taxonomy?show=all">Show all classified jobs</Link>
        )}
        {"  ·  "}
        {jobs.length} shown (max 120)
      </p>

      <table className="data taxonomy-table">
        <thead>
          <tr>
            <th>Job</th>
            <th>Role text</th>
            <th>Families</th>
            <th>Specialties</th>
            <th>Seniority</th>
            <th>Regions</th>
            <th>Status</th>
            <th></th>
          </tr>
        </thead>
        <tbody>
          {jobs.map((job) => {
            const roleFamilies = parseJsonArray(job.roleFamilies);
            const roleSpecialties = parseJsonArray(job.roleSpecialties);
            const locationRegions = parseJsonArray(job.locationRegions);
            const company = formatCompanyName(job.company);
            return (
              <tr key={job.id}>
                <td>
                  <Link href={`/job/${job.id}`}>{company ?? "—"}</Link>
                  <div className="small muted">{job.thread.month} · {snippet(job.rawText, 72)}</div>
                </td>
                <td className="small">
                  {job.role ?? <span className="muted-2">—</span>}
                  <div className={`conf-${job.parseConfidence}`}>{job.parseConfidence}</div>
                </td>
                <td>
                  <form id={`tax-${job.id}`} action={saveTaxonomy}>
                    <input type="hidden" name="id" value={job.id} />
                    <textarea name="roleFamilies" defaultValue={roleFamilies.join(", ")} />
                  </form>
                </td>
                <td><textarea form={`tax-${job.id}`} name="roleSpecialties" defaultValue={roleSpecialties.join(", ")} /></td>
                <td>
                  <select form={`tax-${job.id}`} name="seniority" defaultValue={job.seniority ?? ""}>
                    <option value="">—</option>
                    {SENIORITY_LEVELS.map((level) => <option value={level} key={level}>{level}</option>)}
                  </select>
                </td>
                <td><input form={`tax-${job.id}`} name="locationRegions" defaultValue={locationRegions.join(", ")} /></td>
                <td>
                  <select form={`tax-${job.id}`} name="classificationConfidence" defaultValue={job.classificationConfidence}>
                    <option value="high">high</option>
                    <option value="medium">medium</option>
                    <option value="low">low</option>
                    <option value="unknown">unknown</option>
                  </select>
                  <select form={`tax-${job.id}`} name="needsReview" defaultValue={job.needsReview ? "1" : "0"}>
                    <option value="0">reviewed</option>
                    <option value="1">needs review</option>
                  </select>
                  <input form={`tax-${job.id}`} name="reviewReason" defaultValue={job.reviewReason ?? ""} placeholder="reason" />
                </td>
                <td>
                  <button form={`tax-${job.id}`} className="btn-sm" type="submit">save</button>
                  {job.needsReview && (
                    <form action={markReviewed} style={{ marginTop: 4 }}>
                      <input type="hidden" name="id" value={job.id} />
                      <button className="btn-sm" type="submit">mark ok</button>
                    </form>
                  )}
                </td>
              </tr>
            );
          })}
          {jobs.length === 0 && (
            <tr><td colSpan={8} className="muted">No taxonomy rows match.</td></tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

