import { revalidatePath } from "next/cache";
import { NextResponse } from "next/server";
import { runScheduledIngest } from "@/lib/hn/scheduler";
import { llmEnrichThread } from "@/lib/hn/llm-enrich";
import { prisma } from "@/lib/db";

export const dynamic = "force-dynamic";
export const maxDuration = 300;

// Scheduled ingest endpoint. Fly cron hits this every 15 minutes (see
// fly.toml). The scheduler decides whether to actually scrape based on the
// age of the current month's thread and when we last ingested it.
//
//   Spike (first 48h)  → ingest every tick (~15 min)
//   Maturing (days 2-5) → ingest every ~2 hours
//   Settled (day 6+)    → ingest every ~6 hours
//   No current thread   → check HN for the new month's posting
//
// After a successful ingest, un-enriched posts in the thread are sent to
// Gemini for LLM-assisted extraction (fills gaps the heuristic parser
// missed — salary, seniority, tech tags, etc.).
//
// Protected by CRON_SECRET if set.
export async function GET(req: Request) {
  const secret = process.env.CRON_SECRET;
  if (secret) {
    const auth = req.headers.get("authorization");
    if (auth !== `Bearer ${secret}`) {
      return NextResponse.json({ error: "unauthorized" }, { status: 401 });
    }
  }

  if (process.env.SNAPSHOT_DB === "1") {
    return NextResponse.json({ ok: true, action: "skip", reason: "snapshot mode" });
  }

  if (!process.env.GEMINI_API_KEY) {
    return NextResponse.json({ ok: false, error: "GEMINI_API_KEY not set" }, { status: 500 });
  }

  try {
    const result = await runScheduledIngest();

    // After ingest, run LLM enrichment on the ingested thread.
    if (result.ingestResult) {
      revalidatePath("/");
      revalidatePath("/threads");
      const thread = await prisma.thread.findUnique({
        where: { hnId: result.ingestResult.hnId },
        select: { id: true },
      });
      if (thread) {
        const enrichResult = await llmEnrichThread(thread.id);
        return NextResponse.json({ ok: true, ...result, llmEnrich: enrichResult });
      }
    }

    return NextResponse.json({ ok: true, ...result });
  } catch (e) {
    return NextResponse.json({ ok: false, error: String(e) }, { status: 500 });
  }
}

