import { NextResponse } from "next/server";
import { prisma } from "@/lib/db";
import { parseJsonArray } from "@/lib/format";

export const dynamic = "force-dynamic";

// GET /api/jobs/[id] — single posting with raw text + parsed fields.
export async function GET(_req: Request, { params }: { params: { slug: string } }) {
  const id = Number(params.slug);
  if (!Number.isFinite(id)) {
    return NextResponse.json({ error: "invalid id" }, { status: 400 });
  }
  const j = await prisma.job.findFirst({
    where: { id, hidden: false },
    include: { thread: { select: { month: true, title: true, hnId: true } } },
  });
  if (!j) return NextResponse.json({ error: "not found" }, { status: 404 });

  return NextResponse.json({
    id: j.id,
    hnCommentId: j.hnCommentId,
    thread: j.thread,
    company: j.company,
    website: j.websiteUrl,
    role: j.role,
    roles: parseJsonArray(j.roles),
    roleFamilies: parseJsonArray(j.roleFamilies),
