import { NextResponse } from "next/server";
import { prisma } from "@/lib/db";
import { parseJsonArray } from "@/lib/format";
import { jobMatchesFilters, parseJobFilters, sortJobsForDirectory } from "@/lib/job-filters";

export const dynamic = "force-dynamic";

// GET /api/jobs?month=2026-05&remote=1&visa=1&intern=1&tag=React&family=Backend&region=US&apply=link&seniority=Senior&salary=disclosed&q=...&limit=200
export async function GET(req: Request) {
  const url = new URL(req.url);
  const month = url.searchParams.get("month") ?? undefined;
  const filters = parseJobFilters(url.searchParams, "newest");
  const limit = Math.min(Number(url.searchParams.get("limit") ?? 500) || 500, 2000);

  const rows = await prisma.job.findMany({
    where: {
      hidden: false,
      ...(month ? { thread: { month } } : {}),
      ...(filters.remote ? { remote: true } : {}),
      ...(filters.visa ? { visa: true } : {}),
      ...(filters.intern ? { intern: true } : {}),
    },
    include: { thread: { select: { month: true } } },
    orderBy: { postedAt: "desc" },
    take: 2000,
  });

  const jobs = sortJobsForDirectory(
    rows.filter((j) => jobMatchesFilters(j, filters)),
    filters.sort
  )
    .slice(0, limit)
    .map((j) => ({
      id: j.id,
      hnCommentId: j.hnCommentId,
      month: j.thread.month,
      company: j.company,
      website: j.websiteUrl,
      role: j.role,
      roles: parseJsonArray(j.roles),
      roleFamilies: parseJsonArray(j.roleFamilies),
      roleSpecialties: parseJsonArray(j.roleSpecialties),
      seniority: j.seniority,
      employmentType: j.employmentType,
      location: j.locationDisplay,
      locations: parseJsonArray(j.locations),
      locationRegions: parseJsonArray(j.locationRegions),
      remote: j.remote,
      onsite: j.onsite,
      hybrid: j.hybrid,
      remoteScope: j.remoteScope,
      visa: j.visa,
      intern: j.intern,
      salary: {
        min: j.salaryMin,
        max: j.salaryMax,
        currency: j.salaryCurrency,
        period: j.salaryPeriod,
        equity: j.equity,
        text: j.salaryText,
      },
      tags: parseJsonArray(j.tags),
      salaryBucket: j.salaryBucket,
      apply: { method: j.applyMethod, url: j.applyUrl, email: j.applyEmail },
      enrichment: {
        status: j.enrichmentStatus,
        version: j.enrichmentVersion,
        notes: j.enrichmentNotes,
        enrichedAt: j.enrichedAt,
      },
      author: j.author,
      postedAt: j.postedAt,
      hnUrl: j.hnUrl,
      parseConfidence: j.parseConfidence,
      classificationConfidence: j.classificationConfidence,
      url: `/job/${j.id}`,
    }));

  return NextResponse.json({ count: jobs.length, jobs });
}

