import { prisma } from "@/lib/db";
import { formatCompanyName, snippet } from "@/lib/format";
import { jobMatchesFilters, parseJobFilters, sortJobsForDirectory } from "@/lib/job-filters";

export const revalidate = 300;

function escapeXml(s: string): string {
  return s
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&apos;");
}

// RSS feed of the most recent postings.
export async function GET(req: Request) {
  const url = new URL(req.url);
  const base = process.env.NEXT_PUBLIC_BASE_URL || "http://localhost:3000";
  const month = url.searchParams.get("month") ?? undefined;
  const filters = parseJobFilters(url.searchParams, "newest");
  const rows = await prisma.job.findMany({
    where: {
      hidden: false,
      ...(month ? { thread: { month } } : {}),
      ...(filters.remote ? { remote: true } : {}),
      ...(filters.visa ? { visa: true } : {}),
      ...(filters.intern ? { intern: true } : {}),
    },
    orderBy: { postedAt: "desc" },
    take: 2000,
  });
  const jobs = sortJobsForDirectory(
    rows.filter((j) => jobMatchesFilters(j, filters)),
    filters.sort
  ).slice(0, 100);
  const feedQs = url.searchParams.toString();
  const feedLink = `${base}${feedQs ? `/?${feedQs}` : ""}`;

  const items = jobs
    .map((j) => {
      const title = [formatCompanyName(j.company), j.role].filter(Boolean).join(" — ") || "Job posting";
      const link = `${base}/job/${j.id}`;
      return `    <item>
      <title>${escapeXml(title)}</title>
      <link>${escapeXml(link)}</link>
      <guid isPermaLink="false">hn-${j.hnCommentId}</guid>
      <pubDate>${j.postedAt.toUTCString()}</pubDate>
      <description>${escapeXml(snippet(j.rawText, 280))}</description>
    </item>`;
    })
    .join("\n");

  const xml = `<?xml version="1.0" encoding="UTF-8"?>
<rss version="2.0">
  <channel>
    <title>HN Jobs</title>
    <link>${escapeXml(feedLink)}</link>
    <description>Filtered postings from Hacker News “Who is hiring?” threads.</description>
${items}
  </channel>
</rss>`;

  return new Response(xml, {
    headers: { "content-type": "application/rss+xml; charset=utf-8" },
  });
}

