export const revalidate = 300;

import Link from "next/link";
import { notFound } from "next/navigation";
import type { Metadata } from "next";
import { prisma } from "@/lib/db";
import { parseJsonArray, formatCompanyName, formatMonth, formatDate, formatSalary, hostLabel, snippet } from "@/lib/format";

function applyMethodLabel(method: string): string {
  switch (method) {
    case "link": return "Application link";
    case "email": return "Email";
    case "hn-reply": return "Reply on Hacker News";
    default: return "See posting";
  }
}

async function getJob(slug: string) {
  const id = Number(slug);
  if (!Number.isFinite(id)) return null;
  return prisma.job.findFirst({
    where: { id, hidden: false },
    include: { thread: true },
  });
}

export async function generateMetadata({
  params,
}: {
  params: { slug: string };
}): Promise<Metadata> {
  const job = await getJob(params.slug);
  if (!job) return { title: "Posting not found · HN Jobs" };
  const title = [formatCompanyName(job.company), job.role].filter(Boolean).join(" — ") || "Job posting";
  return {
    title: `${title} · HN Jobs`,
    description: snippet(job.rawText, 150),
  };
}

export default async function JobPage({ params }: { params: { slug: string } }) {
  const job = await getJob(params.slug);
  if (!job) notFound();

  const tags = parseJsonArray(job.tags);
  const roles = parseJsonArray(job.roles);
  const roleFamilies = parseJsonArray(job.roleFamilies);
  const roleSpecialties = parseJsonArray(job.roleSpecialties);
  const locations = parseJsonArray(job.locations);
  const locationRegions = parseJsonArray(job.locationRegions);
  const salary = formatSalary(job.salaryMin, job.salaryMax, job.salaryCurrency, job.salaryPeriod);
  const company = formatCompanyName(job.company);

  return (
    <div>
      <p className="results-info">
        <Link href="/">← All postings</Link>
        {"  ·  "}
        <Link href={`/?month=${job.thread.month}`}>{formatMonth(job.thread.month)} thread</Link>
      </p>

      <h2 style={{ margin: "0 0 2px", fontSize: "18px" }}>
        {company ?? "Job posting"}
        {job.parseConfidence !== "parsed" && (
          <span className="muted-2 small"> (auto-parsed{job.parseConfidence === "raw-only" ? " — see raw text" : ""})</span>
        )}
      </h2>
      {job.role && <p className="muted" style={{ margin: "0 0 12px" }}>{job.role}</p>}

      <table className="fact-table">
        <tbody>
          {company && (
            <tr><th>Company</th><td>{company}</td></tr>
          )}
          {job.websiteUrl && (
            <tr>
              <th>Website</th>
              <td>
                <a href={job.websiteUrl} target="_blank" rel="noopener noreferrer">
                  {hostLabel(job.websiteUrl)} ↗
                </a>
              </td>
            </tr>
          )}
          {roles.length > 1 ? (
            <tr>
              <th>Roles</th>
              <td>
                <ul style={{ margin: 0, paddingLeft: 16 }}>
                  {roles.map((r) => <li key={r}>{r}</li>)}
                </ul>
              </td>
            </tr>
          ) : job.role ? (
            <tr><th>Role</th><td>{job.role}</td></tr>
          ) : null}
          {job.employmentType && (
            <tr><th>Type</th><td>{job.employmentType}</td></tr>
          )}
          {(roleFamilies.length > 0 || job.seniority) && (
            <tr>
              <th>Role taxonomy</th>
              <td className="tags">
                {roleFamilies.map((f) => (
                  <Link key={f} href={`/?family=${encodeURIComponent(f)}`} className="t">{f}</Link>
                ))}
                {job.seniority && (
                  <Link href={`/?seniority=${encodeURIComponent(job.seniority)}`} className="t">
                    {job.seniority}
                  </Link>
                )}
              </td>
            </tr>
          )}
          {roleSpecialties.length > 0 && (
            <tr><th>Specialties</th><td>{roleSpecialties.join(", ")}</td></tr>
          )}
          <tr>
            <th>Location</th>
            <td>
              {job.locationDisplay ?? <span className="muted-2">—</span>}
              {job.hybrid && !/(hybrid)/i.test(job.locationDisplay ?? "") && (
                <span className="pill hybrid">hybrid</span>
              )}
            </td>
          </tr>
          <tr>
            <th>Salary</th>
            <td>
              {salary ? (
                <>
                  <span className="val">{salary}</span>
