import "./globals.css";
import Link from "next/link";
import type { Metadata } from "next";
import { HeaderNav } from "@/components/HeaderNav";

export const metadata: Metadata = {
  title: "HN Jobs",
  description: "A searchable index of Hacker News “Who is hiring?” job postings.",
  alternates: {
    types: { "application/rss+xml": "/api/rss" },
  },
};

export default function RootLayout({ children }: { children: React.ReactNode }) {
  return (
    <html lang="en">
      <head>
        <script defer src="https://cloud.umami.is/script.js" data-website-id="59884197-9fdd-41b0-836c-86ec465ab396" />
      </head>
      <body>
        <div className="site">
          <header className="header">
            <h1>
              <Link href="/">HN Jobs</Link>
            </h1>
            <HeaderNav />
          </header>
          <p className="tagline">
            A searchable index of Hacker News &ldquo;Who is hiring?&rdquo; job postings.
          </p>
          {children}
          <footer className="footer">
            <Link href="/api/jobs">JSON API</Link>
            {" · "}
            <Link href="/api/rss">RSS feed</Link>
            {" · "}
            <a href="https://news.ycombinator.com/submitted?id=whoishiring">Source threads on HN</a>
            {" · "}
            <Link href="/privacy">Privacy</Link>
          </footer>
        </div>
      </body>
    </html>
  );
}

import { redirect } from "next/navigation";
import { headers } from "next/headers";
import { adminConfigured, isAdmin, signInWithPassword } from "@/lib/auth";
import { checkRateLimit, resetRateLimit } from "@/lib/rate-limit";

// Login lives OUTSIDE /admin on purpose: the /admin layout is an auth gate that
// redirects unauthenticated users to /login. If login were under /admin it would
// infinite-redirect. Same reason logout is a route handler, not a page.
export const dynamic = "force-dynamic";

async function login(formData: FormData) {
  "use server";

  const hdrs = await headers();
  const ip =
    hdrs.get("x-forwarded-for")?.split(",")[0].trim() ??
    hdrs.get("x-real-ip") ??
    "unknown";

  const { allowed } = checkRateLimit(ip);
  if (!allowed) {
    redirect("/login?error=locked");
  }

  const password = String(formData.get("password") ?? "");
  const ok = await signInWithPassword(password);
  if (ok) {
    resetRateLimit(ip);
    redirect("/admin");
  }

  redirect("/login?error=1");
}

export default async function LoginPage({
  searchParams,
}: {
  searchParams: { error?: string };
}) {
  if (await isAdmin()) redirect("/admin");

  if (!adminConfigured()) {
    return (
      <div style={{ maxWidth: 600 }}>
        <h2 className="section">Admin is not configured</h2>
        <p>
          Set <code>ADMIN_PASSWORD</code> in <code>.env</code> (minimum 4
          characters), then restart <code>npm run dev</code>.
        </p>
      </div>
    );
  }

  const error = searchParams.error === "1";
  const locked = searchParams.error === "locked";

  return (
    <div style={{ maxWidth: 360 }}>
      <h2 className="section">Admin sign in</h2>
      <form className="submit-form" action={login}>
        <label htmlFor="password">Password</label>
        <input id="password" name="password" type="password" autoComplete="current-password" autoFocus required />
        {error && (
          <p className="small" style={{ color: "var(--error)", marginTop: 6 }}>
            Incorrect password.
          </p>
        )}
        {locked && (
          <p className="small" style={{ color: "var(--error)", marginTop: 6 }}>
            Too many attempts. Try again in 15 minutes.
          </p>
        )}
        <button type="submit">Sign in</button>
      </form>
    </div>
  );
}

