  const { allowed } = checkRateLimit(ip);
  if (!allowed) {
    redirect("/login?error=locked");
  }

  const password = String(formData.get("password") ?? "");
  const ok = await signInWithPassword(password);
  if (ok) {
    resetRateLimit(ip);
    redirect("/admin");
  }

  redirect("/login?error=1");
}

