import Link from "next/link";
import { prisma } from "@/lib/db";
import { parseJsonArray, formatCompanyName, formatMonth, formatSalary, hostLabel } from "@/lib/format";
import { resolveMonthFilter } from "@/lib/month-filter";
import {
  applyBucketsForJob,
  applyFilterLabel,
  hasPublicListingSignal,
  jobMatchesFilters,
  parseJobFilters,
  sortJobsForDirectory,
  type ApplyFilter,
} from "@/lib/job-filters";
import { SearchableFilter, type FilterItem } from "@/components/SearchableFilter";
import { FiltersSidebar } from "@/components/FiltersSidebar";

export const revalidate = 60;

type SearchParams = { [k: string]: string | string[] | undefined };

function one(v: string | string[] | undefined): string | undefined {
  return Array.isArray(v) ? v[0] : v;
}

// Build an href for the directory with one param changed (toggle off if equal).
function buildHref(params: SearchParams, key: string, value: string | null): string {
  const sp = new URLSearchParams();
  for (const [k, v] of Object.entries(params)) {
    const val = one(v);
    if (val && k !== key) sp.set(k, val);
  }
  if (value !== null) {
    const current = one(params[key]);
    if (current !== value) sp.set(key, value);
  }
  const qs = sp.toString();
  return qs ? `/?${qs}` : "/";
}

export default async function DirectoryPage({
  searchParams,
}: {
  searchParams: SearchParams;
}) {
  const filters = parseJobFilters(searchParams);
  const q = filters.q;
  const requestedMonth = one(searchParams.month);
  const { tag, family, seniority, salary, region, apply, remote, visa, intern, sort } = filters;

  const months = await prisma.thread.findMany({
    orderBy: { month: "desc" },
    select: { month: true, jobCount: true },
  });
  const latestMonth = months[0]?.month;
  const { effectiveMonth } = resolveMonthFilter(requestedMonth, latestMonth);

  // Pull the candidate set from the DB (month filter applied server-side),
  // then do text/flag/tag filtering + faceting in JS. Fine at thread scale.
  const jobs = await prisma.job.findMany({
    where: {
      hidden: false,
      ...(effectiveMonth ? { thread: { month: effectiveMonth } } : {}),
    },
    include: { thread: { select: { month: true, title: true } } },
    orderBy: { postedAt: "desc" },
  });

  const publicJobs = jobs.filter(hasPublicListingSignal);

  // Facets computed before flag/tag/text filtering so counts stay meaningful.
  const tagCounts = new Map<string, number>();
  const familyCounts = new Map<string, number>();
  const seniorityCounts = new Map<string, number>();
  const regionCounts = new Map<string, number>();
  const applyCounts = new Map<ApplyFilter, number>();
  let salaryDisclosedCount = 0;
  for (const j of publicJobs) {
    for (const t of parseJsonArray(j.tags)) {
      tagCounts.set(t, (tagCounts.get(t) ?? 0) + 1);
    }
    for (const f of parseJsonArray(j.roleFamilies)) {
      familyCounts.set(f, (familyCounts.get(f) ?? 0) + 1);
    }
    if (j.seniority) seniorityCounts.set(j.seniority, (seniorityCounts.get(j.seniority) ?? 0) + 1);
    for (const r of parseJsonArray(j.locationRegions)) {
      regionCounts.set(r, (regionCounts.get(r) ?? 0) + 1);
    }
    for (const bucket of applyBucketsForJob(j)) {
      applyCounts.set(bucket, (applyCounts.get(bucket) ?? 0) + 1);
    }
    if (j.salaryBucket === "disclosed") salaryDisclosedCount++;
  }

  const filtered = sortJobsForDirectory(
    publicJobs.filter((j) => jobMatchesFilters(j, filters)),
    sort
  );

  const monthItems: FilterItem[] = months.map((m) => ({
    label: formatMonth(m.month),
    href: buildHref(searchParams, "month", m.month),
    count: m.jobCount,
    active: effectiveMonth === m.month,
  }));

  const tagItems: FilterItem[] = Array.from(tagCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .map(([label, count]) => ({
      label,
      href: buildHref(searchParams, "tag", label),
      count,
      active: tag === label,
    }));

  const familyItems: FilterItem[] = Array.from(familyCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .map(([label, count]) => ({
      label,
      href: buildHref(searchParams, "family", label),
      count,
      active: family === label,
    }));

  const seniorityItems: FilterItem[] = Array.from(seniorityCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .map(([label, count]) => ({
      label,
      href: buildHref(searchParams, "seniority", label),
      count,
      active: seniority === label,
    }));

  const regionItems: FilterItem[] = Array.from(regionCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .map(([label, count]) => ({
      label,
      href: buildHref(searchParams, "region", label),
      count,
      active: region === label,
    }));

  const applyOrder: ApplyFilter[] = ["link", "email", "hn-reply", "missing"];
  const applyItems: FilterItem[] = applyOrder.map((key) => ({
    label: applyFilterLabel(key) ?? key,
    href: buildHref(searchParams, "apply", key),
    count: applyCounts.get(key) ?? 0,
    active: apply === key,
  }));

  const flagItems: FilterItem[] = [
    { label: "Remote", href: buildHref(searchParams, "remote", "1"), active: remote },
    { label: "Sponsors visa", href: buildHref(searchParams, "visa", "1"), active: visa },
    { label: "Interns welcome", href: buildHref(searchParams, "intern", "1"), active: intern },
  ];

  const salaryItems: FilterItem[] = [
    {
      label: "Salary disclosed",
      href: buildHref(searchParams, "salary", "disclosed"),
      count: salaryDisclosedCount,
      active: salary === "disclosed",
    },
  ];

  const sortItems: FilterItem[] = [
    { label: "Company A–Z", href: buildHref(searchParams, "sort", "company"), active: sort === "company" },
    { label: "Newest", href: buildHref(searchParams, "sort", "newest"), active: sort === "newest" },
    { label: "Salary high", href: buildHref(searchParams, "sort", "salary-desc"), active: sort === "salary-desc" },
  ];

  const activeCount =
    (effectiveMonth && effectiveMonth !== latestMonth ? 1 : 0) +
    (tag ? 1 : 0) +
    (family ? 1 : 0) +
    (seniority ? 1 : 0) +
    (salary ? 1 : 0) +
    (region ? 1 : 0) +
    (apply ? 1 : 0) +
    (remote ? 1 : 0) +
    (visa ? 1 : 0) +
    (intern ? 1 : 0);

  return (
    <div className="layout">
      <FiltersSidebar activeCount={activeCount}>
        <form className="search-form" action="/" method="get">
          {requestedMonth && <input type="hidden" name="month" value={requestedMonth} />}
          {tag && <input type="hidden" name="tag" value={tag} />}
          {family && <input type="hidden" name="family" value={family} />}
          {seniority && <input type="hidden" name="seniority" value={seniority} />}
          {salary && <input type="hidden" name="salary" value={salary} />}
          {region && <input type="hidden" name="region" value={region} />}
          {apply && <input type="hidden" name="apply" value={apply} />}
          {sort !== "company" && <input type="hidden" name="sort" value={sort} />}
          {remote && <input type="hidden" name="remote" value="1" />}
          {visa && <input type="hidden" name="visa" value="1" />}
          {intern && <input type="hidden" name="intern" value="1" />}
          <input
            className="searchbox"
            type="text"
            name="q"
            placeholder="Search postings…"
            defaultValue={q}
          />
        </form>
        <SearchableFilter title="Sort" items={sortItems} />
        <SearchableFilter title="Filters" items={flagItems} />
        <SearchableFilter
          title="Role"
          items={familyItems}
          searchable
          clearHref={buildHref(searchParams, "family", null)}
        />
        <SearchableFilter
          title="Seniority"
          items={seniorityItems}
          searchable={seniorityItems.length > 8}
          clearHref={buildHref(searchParams, "seniority", null)}
        />
        <SearchableFilter
          title="Region"
          items={regionItems}
          searchable={regionItems.length > 8}
          clearHref={buildHref(searchParams, "region", null)}
        />
        <SearchableFilter
          title="Apply"
          items={applyItems}
          clearHref={buildHref(searchParams, "apply", null)}
        />
        <SearchableFilter
          title="Comp"
          items={salaryItems}
          clearHref={buildHref(searchParams, "salary", null)}
        />
        <SearchableFilter
          title="Tech"
          items={tagItems}
          searchable
          clearHref={buildHref(searchParams, "tag", null)}
        />
        <SearchableFilter
          title="Month"
          items={monthItems}
          searchable={monthItems.length > 8}
        />
      </FiltersSidebar>

      <main>
        <table className="data">
          <thead>
            <tr>
              <th>Company</th>
              <th>Role</th>
              <th>Location</th>
              <th>Salary</th>
              <th>Tech</th>
              <th>Apply</th>
              <th>Details</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map((j) => {
              const tags = parseJsonArray(j.tags);
              const roles = parseJsonArray(j.roles);
              const salary = formatSalary(j.salaryMin, j.salaryMax, j.salaryCurrency, j.salaryPeriod);
              const company = formatCompanyName(j.company);
              const websiteLabel = hostLabel(j.websiteUrl);
              const companyLabel = company ?? websiteLabel;
              const roleLines = roles.length > 0 ? roles : j.role ? [j.role] : [];
              const hiringFacts = [
                j.visa ? "visa sponsorship" : null,
                j.intern ? "interns welcome" : null,
              ].filter((fact): fact is string => !!fact);
              return (
                <tr key={j.id}>
                  <td>
                    {companyLabel && j.websiteUrl ? (
                      <a
                        href={j.websiteUrl}
                        target="_blank"
                        rel="noopener noreferrer"
                        className={company ? `conf-${j.parseConfidence}` : "muted-2"}
                      >
                        {companyLabel}
                      </a>
                    ) : companyLabel ? (
                      <span className={company ? `conf-${j.parseConfidence}` : "muted-2"}>
                        {companyLabel}
                      </span>
                    ) : (
                      <span className="muted-2">—</span>
                    )}
                  </td>
                  <td>
                    {roleLines.length > 0 ? (
                      <div className="line-list role-list">
                        {roleLines.map((role) => <div key={role}>{role}</div>)}
                      </div>
                    ) : (
                      <span className="muted-2">—</span>
                    )}
                    {hiringFacts.length > 0 && (
                      <div className="row-facts">
                        {hiringFacts.map((fact) => <span key={fact}>{fact}</span>)}
                      </div>
                    )}
                  </td>
                  <td className="tag">{j.locationDisplay ?? <span className="muted-2">—</span>}</td>
                  <td className="num">
                    {salary ?? <span className="muted-2">—</span>}
                    {j.equity && <span className="muted-2 small"> +eq</span>}
                  </td>
                  <td className="tags">
                    {tags.slice(0, 4).map((t) => (
                      <span className="t" key={t}>{t}</span>
                    ))}
                  </td>
                  <td className="small">
                    {j.applyUrl ? (
                      <a href={j.applyUrl} target="_blank" rel="noopener noreferrer">apply ↗</a>
                    ) : j.applyEmail ? (
                      <a href={`mailto:${j.applyEmail}`}>email ↗</a>
                    ) : (
                      <span className="muted-2">—</span>
                    )}
                  </td>
                  <td className="small">
                    <Link href={`/job/${j.id}`} prefetch={false}>details</Link>
                  </td>
                </tr>
              );
            })}
            {filtered.length === 0 && (
              <tr>
                <td colSpan={7} className="muted" style={{ padding: "12px" }}>
                  No postings match. Try clearing filters, or run an ingest if the
                  database is empty (<code>npm run ingest</code>).
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </main>
    </div>
  );
}

