}: {
  searchParams: SearchParams;
}) {
  const filters = parseJobFilters(searchParams);
  const q = filters.q;
  const requestedMonth = one(searchParams.month);
  const { tag, family, seniority, salary, region, apply, remote, visa, intern, sort } = filters;

  const months = await prisma.thread.findMany({
    orderBy: { month: "desc" },
    select: { month: true, jobCount: true },
  });
  const latestMonth = months[0]?.month;
  const { effectiveMonth } = resolveMonthFilter(requestedMonth, latestMonth);

  // Pull the candidate set from the DB (month filter applied server-side),
  // then do text/flag/tag filtering + faceting in JS. Fine at thread scale.
  const jobs = await prisma.job.findMany({
    where: {
      hidden: false,
      ...(effectiveMonth ? { thread: { month: effectiveMonth } } : {}),
    },
    include: { thread: { select: { month: true, title: true } } },
    orderBy: { postedAt: "desc" },
  });

  const publicJobs = jobs.filter(hasPublicListingSignal);

