  const tagCounts = new Map<string, number>();
  const familyCounts = new Map<string, number>();
  const seniorityCounts = new Map<string, number>();
  const regionCounts = new Map<string, number>();
  const applyCounts = new Map<ApplyFilter, number>();
  let salaryDisclosedCount = 0;
  for (const j of publicJobs) {
    for (const t of parseJsonArray(j.tags)) {
      tagCounts.set(t, (tagCounts.get(t) ?? 0) + 1);
    }
    for (const f of parseJsonArray(j.roleFamilies)) {
      familyCounts.set(f, (familyCounts.get(f) ?? 0) + 1);
    }
    if (j.seniority) seniorityCounts.set(j.seniority, (seniorityCounts.get(j.seniority) ?? 0) + 1);
    for (const r of parseJsonArray(j.locationRegions)) {
      regionCounts.set(r, (regionCounts.get(r) ?? 0) + 1);
    }
    for (const bucket of applyBucketsForJob(j)) {
      applyCounts.set(bucket, (applyCounts.get(bucket) ?? 0) + 1);
    }
    if (j.salaryBucket === "disclosed") salaryDisclosedCount++;
  }

  const filtered = sortJobsForDirectory(
    publicJobs.filter((j) => jobMatchesFilters(j, filters)),
    sort
  );

  const monthItems: FilterItem[] = months.map((m) => ({
    label: formatMonth(m.month),
    href: buildHref(searchParams, "month", m.month),
    count: m.jobCount,
    active: effectiveMonth === m.month,
  }));

  const tagItems: FilterItem[] = Array.from(tagCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .map(([label, count]) => ({
      label,
      href: buildHref(searchParams, "tag", label),
      count,
      active: tag === label,
    }));

  const familyItems: FilterItem[] = Array.from(familyCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .map(([label, count]) => ({
      label,
      href: buildHref(searchParams, "family", label),
      count,
      active: family === label,
    }));

  const seniorityItems: FilterItem[] = Array.from(seniorityCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .map(([label, count]) => ({
      label,
      href: buildHref(searchParams, "seniority", label),
      count,
      active: seniority === label,
    }));

  const regionItems: FilterItem[] = Array.from(regionCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .map(([label, count]) => ({
      label,
      href: buildHref(searchParams, "region", label),
      count,
      active: region === label,
    }));

  const applyOrder: ApplyFilter[] = ["link", "email", "hn-reply", "missing"];
  const applyItems: FilterItem[] = applyOrder.map((key) => ({
    label: applyFilterLabel(key) ?? key,
    href: buildHref(searchParams, "apply", key),
    count: applyCounts.get(key) ?? 0,
    active: apply === key,
  }));

  const flagItems: FilterItem[] = [
    { label: "Remote", href: buildHref(searchParams, "remote", "1"), active: remote },
    { label: "Sponsors visa", href: buildHref(searchParams, "visa", "1"), active: visa },
    { label: "Interns welcome", href: buildHref(searchParams, "intern", "1"), active: intern },
  ];

  const salaryItems: FilterItem[] = [
    {
      label: "Salary disclosed",
      href: buildHref(searchParams, "salary", "disclosed"),
      count: salaryDisclosedCount,
      active: salary === "disclosed",
    },
  ];

  const sortItems: FilterItem[] = [
    { label: "Company A–Z", href: buildHref(searchParams, "sort", "company"), active: sort === "company" },
    { label: "Newest", href: buildHref(searchParams, "sort", "newest"), active: sort === "newest" },
    { label: "Salary high", href: buildHref(searchParams, "sort", "salary-desc"), active: sort === "salary-desc" },
  ];

  const activeCount =
    (effectiveMonth && effectiveMonth !== latestMonth ? 1 : 0) +
    (tag ? 1 : 0) +
    (family ? 1 : 0) +
    (seniority ? 1 : 0) +
    (salary ? 1 : 0) +
    (region ? 1 : 0) +
    (apply ? 1 : 0) +
    (remote ? 1 : 0) +
    (visa ? 1 : 0) +
    (intern ? 1 : 0);

  return (
    <div className="layout">
      <FiltersSidebar activeCount={activeCount}>
        <form className="search-form" action="/" method="get">
          {requestedMonth && <input type="hidden" name="month" value={requestedMonth} />}
          {tag && <input type="hidden" name="tag" value={tag} />}
          {family && <input type="hidden" name="family" value={family} />}
          {seniority && <input type="hidden" name="seniority" value={seniority} />}
          {salary && <input type="hidden" name="salary" value={salary} />}
          {region && <input type="hidden" name="region" value={region} />}
          {apply && <input type="hidden" name="apply" value={apply} />}
          {sort !== "company" && <input type="hidden" name="sort" value={sort} />}
          {remote && <input type="hidden" name="remote" value="1" />}
          {visa && <input type="hidden" name="visa" value="1" />}
          {intern && <input type="hidden" name="intern" value="1" />}
          <input
            className="searchbox"
            type="text"
            name="q"
            placeholder="Search postings…"
            defaultValue={q}
          />
        </form>
        <SearchableFilter title="Sort" items={sortItems} />
        <SearchableFilter title="Filters" items={flagItems} />
        <SearchableFilter
          title="Role"
          items={familyItems}
          searchable
          clearHref={buildHref(searchParams, "family", null)}
        />
        <SearchableFilter
          title="Seniority"
          items={seniorityItems}
          searchable={seniorityItems.length > 8}
          clearHref={buildHref(searchParams, "seniority", null)}
        />
        <SearchableFilter
