"use client";

import { useState } from "react";
import Link from "next/link";

export interface FilterItem {
  label: string;
  href: string;
  count?: number;
  active?: boolean;
}

// A single bordered filter panel with an optional in-list search box.
// The only client state is the search query; selection itself is driven by
// URL search params via the Link hrefs (server-rendered).
export function SearchableFilter({
  title,
  items,
  searchable = false,
  clearHref,
}: {
  title: string;
  items: FilterItem[];
  searchable?: boolean;
  clearHref?: string;
}) {
  const [q, setQ] = useState("");
  const filtered = q
    ? items.filter((i) => i.label.toLowerCase().includes(q.toLowerCase()))
    : items;
  const anyActive = items.some((i) => i.active);

  return (
    <div className="filter-group">
      <h3>{title}</h3>
      {searchable && (
        <input
          className="filter-search"
          placeholder={`Filter ${title.toLowerCase()}…`}
          value={q}
          onChange={(e) => setQ(e.target.value)}
        />
      )}
      <ul>
        {clearHref && anyActive && (
          <li className="clear">
            <Link href={clearHref}>clear</Link>
          </li>
        )}
        {filtered.map((i) => (
          <li key={i.href + i.label}>
            <Link href={i.href} className={i.active ? "active" : ""}>
              {i.label}
              {typeof i.count === "number" && (
                <span className="filter-count">{i.count}</span>
              )}
            </Link>
          </li>
        ))}
        {filtered.length === 0 && (
          <li className="muted-2 small" style={{ padding: "4px 10px" }}>
            no matches
          </li>
        )}
      </ul>
    </div>
  );
}

