export type QualityBucket =
  | "weak-parse"
  | "missing-apply"
  | "taxonomy-review"
  | "enrichment-attention";

export const QUALITY_BUCKETS: QualityBucket[] = [
  "weak-parse",
  "missing-apply",
  "taxonomy-review",
  "enrichment-attention",
];

export interface QualityJobRow {
  parseConfidence: string;
  company: string | null;
  role: string | null;
  applyMethod: string;
  applyUrl: string | null;
  applyEmail?: string | null;
  needsReview: boolean;
  classificationConfidence: string;
  enrichmentStatus: string;
}

export function qualityBucketLabel(value: string): string | null {
  switch (value) {
    case "weak-parse": return "Weak parse";
    case "missing-apply": return "Missing apply path";
    case "taxonomy-review": return "Taxonomy review";
    case "enrichment-attention": return "Enrichment attention";
    default: return null;
  }
}

export function rowMatchesQualityBucket(row: QualityJobRow, bucket: QualityBucket): boolean {
  switch (bucket) {
    case "weak-parse":
      return row.parseConfidence !== "parsed" || !row.company || !row.role;
    case "missing-apply":
      return !row.applyUrl && !row.applyEmail && row.applyMethod !== "hn-reply";
    case "taxonomy-review":
      return row.needsReview || row.classificationConfidence === "low" || row.classificationConfidence === "unknown";
    case "enrichment-attention":
      return row.enrichmentStatus === "pending" || row.enrichmentStatus === "failed";
  }
}

export function qualityBucketCounts(rows: QualityJobRow[]): Record<QualityBucket, number> {
  const counts = Object.fromEntries(QUALITY_BUCKETS.map((bucket) => [bucket, 0])) as Record<QualityBucket, number>;
  for (const row of rows) {
    for (const bucket of QUALITY_BUCKETS) {
      if (rowMatchesQualityBucket(row, bucket)) counts[bucket]++;
    }
  }
  return counts;
}

export function parseQualityBucket(value: string | undefined): QualityBucket {
  return QUALITY_BUCKETS.includes(value as QualityBucket) ? (value as QualityBucket) : "weak-parse";
}

