import { cookies } from "next/headers";
import crypto from "crypto";

// Single shared admin password, hashed into a session cookie. Same scheme as
// Lab Index: no User table, one secret in ADMIN_PASSWORD. If you ever need
// multi-admin, add Auth.js or Clerk — don't extend this.

const COOKIE_NAME = "hnjobs_admin";
const COOKIE_MAX_AGE = 60 * 60 * 24 * 30; // 30 days

function adminPasswordHash(): string | null {
  const pw = process.env.ADMIN_PASSWORD;
  if (!pw || pw.length < 4) return null;
  return crypto.createHash("sha256").update(pw).digest("hex");
}

export async function isAdmin(): Promise<boolean> {
  const expected = adminPasswordHash();
  if (!expected) return false;
  const c = await cookies();
  const got = c.get(COOKIE_NAME)?.value;
  if (!got) return false;

  try {
    return crypto.timingSafeEqual(Buffer.from(got, "hex"), Buffer.from(expected, "hex"));
  } catch {
    return false;
  }
}

export async function signInWithPassword(password: string): Promise<boolean> {
  const expected = process.env.ADMIN_PASSWORD;
  if (!expected || expected.length < 4) return false;
  if (password !== expected) return false;

  const hash = crypto.createHash("sha256").update(password).digest("hex");
  const c = await cookies();
  c.set(COOKIE_NAME, hash, {
    httpOnly: true,
    sameSite: "lax",
    secure: process.env.NODE_ENV === "production",
    path: "/",
    maxAge: COOKIE_MAX_AGE,
  });
  return true;
}

export async function signOut(): Promise<void> {
  const c = await cookies();
  c.delete(COOKIE_NAME);
}

export function adminConfigured(): boolean {
  return adminPasswordHash() != null;
}

