import path from "path";
import { PrismaClient } from "@prisma/client";
import { PrismaClient as SnapshotClient } from "./generated/snapshot";

const globalForPrisma = globalThis as unknown as { prisma?: PrismaClient };

// SNAPSHOT_DB=1 serves the local SQLite snapshot (prisma/snapshot.db,
// written by scripts/snapshot-db.ts) instead of the live Postgres database.
// Same models, so the snapshot client stands in for the main one.
function createClient(): PrismaClient {
  if (process.env.SNAPSHOT_DB === "1") {
    const url =
      process.env.SNAPSHOT_DATABASE_URL ??
      "file:" + path.join(process.cwd(), "prisma", "snapshot.db");
    return new SnapshotClient({
      datasources: { db: { url } },
    }) as unknown as PrismaClient;
  }
  return new PrismaClient({
    log: process.env.NODE_ENV === "development" ? ["warn", "error"] : ["error"],
  });
}

export const prisma = globalForPrisma.prisma ?? createClient();

if (process.env.NODE_ENV !== "production") globalForPrisma.prisma = prisma;

