// Small formatting + JSON helpers, shared across server components.

// Parse a JSON array column safely. Returns [] on null/garbage.
export function parseJsonArray(value: string | null | undefined): string[] {
  if (!value) return [];
  try {
    const parsed = JSON.parse(value);
    return Array.isArray(parsed) ? parsed.filter((x) => typeof x === "string") : [];
  } catch {
    return [];
  }
}

// "2026-05" → "May 2026" for display.
export function formatMonth(month: string): string {
  const [y, m] = month.split("-").map(Number);
  if (!y || !m) return month;
  const date = new Date(Date.UTC(y, m - 1, 1));
  return date.toLocaleString("en-US", { month: "long", year: "numeric", timeZone: "UTC" });
}

// Relative-ish date for feeds, e.g. "May 2, 2026".
export function formatDate(d: Date | string): string {
  const date = typeof d === "string" ? new Date(d) : d;
  return date.toLocaleDateString("en-US", { year: "numeric", month: "short", day: "numeric" });
}

export function formatCompanyName(company: string | null | undefined): string | null {
  if (!company) return null;
  const clean = company.replace(/\s+/g, " ").trim().replace(/^[*•]+\s*/, "").trim();
  if (!clean) return null;
  if (clean.length > 80) return null;
  if (/^(?:\[flagged\]|>|@|posting by\b)/i.test(clean)) return null;
  if (/^(?:i\b|i['’]m\b|we\b|we['’]re\b|hi\b|hey\b|not hiring\b|applied\b|curious\b|don['’]?t\b|good luck\b|sent an email\b|what['’]?s up\b|in addition\b|aggregated\b|edit:|update:|\d+\s+comments\b)/i.test(clean)) {
    return null;
  }
  if (/[!?]{2,}/.test(clean)) return null;
  if (/\b(?:companies|startups|job boards?|search tools?)\b/i.test(clean)) return null;
  return clean;
}

const CURRENCY_SYMBOL: Record<string, string> = {
  USD: "$", EUR: "€", GBP: "£", CAD: "C$", AUD: "A$",
};

// Compact one number: 120000 → "120k", 95000 → "95k", 50 → "50".
function compactAmount(n: number): string {
  if (n >= 1000 && n % 1000 === 0) return `${n / 1000}k`;
  if (n >= 1000) return `${Math.round(n / 1000)}k`;
  return String(n);
}

// Render a normalized salary range, e.g. "$120k–160k/yr" or "€90k/yr".
export function formatSalary(
  min: number | null | undefined,
  max: number | null | undefined,
  currency: string | null | undefined,
  period: string | null | undefined
): string | null {
  if (min == null && max == null) return null;
  const sym = currency ? CURRENCY_SYMBOL[currency] ?? `${currency} ` : "";
  const lo = min != null ? compactAmount(min) : null;
  const hi = max != null ? compactAmount(max) : null;
  let body: string;
  if (lo && hi && lo !== hi) body = `${sym}${lo}–${hi}`;
  else body = `${sym}${lo ?? hi}`;
  const suffix = period === "hour" ? "/hr" : period === "month" ? "/mo" : period === "year" ? "/yr" : "";
  return body + suffix;
}

// Short, readable host label for a URL, e.g. "https://about.acme.com/x" → "acme.com".
export function hostLabel(url: string | null | undefined): string | null {
  if (!url) return null;
  const host = url.replace(/^https?:\/\//i, "").replace(/^www\./i, "").split("/")[0];
  return host || null;
}

// Truncate plain text to a snippet for the directory table.
export function snippet(text: string, max = 180): string {
  const clean = text.replace(/\s+/g, " ").trim();
  if (clean.length <= max) return clean;
  return clean.slice(0, max).replace(/\s+\S*$/, "") + "…";
}

