import { prisma } from "../db";
import { parseJsonArray } from "../format";
import { classifyJobTaxonomy, serializeJobTaxonomy } from "./taxonomy";

const taxonomySelect = {
  id: true,
  role: true,
  roles: true,
  rawText: true,
  tags: true,
  employmentType: true,
  parseConfidence: true,
  intern: true,
  salaryMin: true,
  salaryMax: true,
  locationDisplay: true,
  locations: true,
  remoteScope: true,
};

type TaxonomyJobRow = Awaited<ReturnType<typeof getTaxonomyRows>>[number];

async function getTaxonomyRows(options: { reviewOnly?: boolean; ids?: number[] }) {
  return prisma.job.findMany({
    where: {
      ...(options.reviewOnly ? { needsReview: true } : {}),
      ...(options.ids ? { id: { in: options.ids } } : {}),
    },
    orderBy: { postedAt: "desc" },
    select: taxonomySelect,
  });
}

export function classifyJobRow(job: TaxonomyJobRow) {
  return classifyJobTaxonomy({
    role: job.role,
    roles: parseJsonArray(job.roles),
    rawText: job.rawText,
    tags: parseJsonArray(job.tags),
    employmentType: job.employmentType,
    parseConfidence: job.parseConfidence,
    intern: job.intern,
    salaryMin: job.salaryMin,
    salaryMax: job.salaryMax,
    locationDisplay: job.locationDisplay,
    locations: parseJsonArray(job.locations),
    remoteScope: job.remoteScope,
  });
}

export async function classifyJobs(options: { reviewOnly?: boolean; ids?: number[] } = {}) {
  const jobs = await getTaxonomyRows(options);
  let classified = 0;
  let needsReview = 0;

  for (const job of jobs) {
    const taxonomy = classifyJobRow(job);
    await prisma.job.update({
      where: { id: job.id },
      data: serializeJobTaxonomy(taxonomy),
    });
    classified++;
    if (taxonomy.needsReview) needsReview++;
  }

  return { classified, needsReview };
}

