import { initialEnrichmentData } from "./enrich";
import { parseJob } from "./parse";
import { classifyJobTaxonomy, serializeJobTaxonomy } from "./taxonomy";

// Build the full derived cache for one raw HN posting. This is shared by live
// ingest and local reparse/backfill scripts so parser/taxonomy/enrichment state
// do not drift.
export function deriveJobCache(
  rawText: string,
  rawHtml?: string,
  options: { author?: string | null } = {}
) {
  const parsed = parseJob(rawText, rawHtml, { author: options.author });
  const taxonomy = classifyJobTaxonomy({
    role: parsed.role,
    roles: parsed.roles,
    rawText,
    tags: parsed.tags,
    employmentType: parsed.employmentType,
    parseConfidence: parsed.parseConfidence,
    intern: parsed.intern,
    salaryMin: parsed.salary.min,
    salaryMax: parsed.salary.max,
    locationDisplay: parsed.location.display,
    locations: parsed.location.places,
    remoteScope: parsed.location.remoteScope,
  });

  return {
    company: parsed.company,
    websiteUrl: parsed.website,
    role: parsed.role,
    roles: JSON.stringify(parsed.roles),
    employmentType: parsed.employmentType,
    locationDisplay: parsed.location.display,
    locations: JSON.stringify(parsed.location.places),
    remote: parsed.remote,
    onsite: parsed.onsite,
    hybrid: parsed.hybrid,
    remoteScope: parsed.location.remoteScope,
    visa: parsed.visa,
    intern: parsed.intern,
    salaryText: parsed.salary.text,
    salaryMin: parsed.salary.min,
    salaryMax: parsed.salary.max,
    salaryCurrency: parsed.salary.currency,
    salaryPeriod: parsed.salary.period,
    equity: parsed.salary.equity,
    applyMethod: parsed.apply.method,
    applyUrl: parsed.apply.url,
    applyEmail: parsed.apply.email,
    ...initialEnrichmentData({
      websiteUrl: parsed.website,
      applyMethod: parsed.apply.method,
      applyUrl: parsed.apply.url,
      applyEmail: parsed.apply.email,
    }),
    tags: JSON.stringify(parsed.tags),
    parseConfidence: parsed.parseConfidence,
    ...serializeJobTaxonomy(taxonomy),
  };
}

import { prisma } from "../db";
import { enrichApplyLink } from "./enrich";

export async function enrichJobs(
  options: { limit?: number; retry?: boolean; concurrency?: number } = {}
) {
  const limit = Math.min(Math.max(options.limit ?? 50, 1), 500);
  const concurrency = Math.min(Math.max(options.concurrency ?? 5, 1), 10);
  const statuses = options.retry ? ["pending", "missed", "failed"] : ["pending"];
  const jobs = await prisma.job.findMany({
    where: {
      applyUrl: null,
      websiteUrl: { not: null },
      enrichmentStatus: { in: statuses },
    },
    orderBy: { postedAt: "desc" },
    take: limit,
    select: {
      id: true,
      websiteUrl: true,
      applyMethod: true,
      applyUrl: true,
      applyEmail: true,
    },
  });

  let enriched = 0;
  let missed = 0;
  let failed = 0;
  for (let i = 0; i < jobs.length; i += concurrency) {
    const batch = jobs.slice(i, i + concurrency);
    const results = await Promise.all(
      batch.map(async (job) => {
        const result = await enrichApplyLink({
          websiteUrl: job.websiteUrl,
          applyMethod: job.applyMethod,
          applyUrl: job.applyUrl,
          applyEmail: job.applyEmail,
        });
        await prisma.job.update({
          where: { id: job.id },
          data: result,
        });
        return result.enrichmentStatus;
      })
    );
    for (const status of results) {
      if (status === "enriched") enriched++;
      else if (status === "failed") failed++;
      else if (status === "missed") missed++;
    }
  }

  return { scanned: jobs.length, enriched, missed, failed };
}

