// Optional enrichment for derived application links.
//
// This module is deliberately separate from parsing. Parsing only uses text HN
// already gave us; enrichment may probe a company website for a careers page.
// The raw HN snapshot is never touched.

export const ENRICHMENT_VERSION = "careers-v1";

export type EnrichmentStatus = "pending" | "enriched" | "missed" | "skipped" | "failed";

export interface ApplyLinkInput {
  websiteUrl: string | null;
  applyMethod: string;
  applyUrl: string | null;
  applyEmail: string | null;
}

export interface ApplyLinkEnrichment {
  applyMethod: string;
  applyUrl: string | null;
  applyEmail: string | null;
  enrichmentStatus: EnrichmentStatus;
  enrichmentVersion: string;
  enrichmentNotes: string | null;
  enrichedAt: Date | null;
}

export interface FetchLikeResponse {
  ok: boolean;
  status: number;
  text?: () => Promise<string>;
}

export type FetchLike = (url: string, init?: RequestInit) => Promise<FetchLikeResponse>;

export function candidateCareersUrls(websiteUrl: string | null): string[] {
  if (!websiteUrl) return [];
  let origin: string;
  try {
    origin = new URL(websiteUrl).origin;
  } catch {
    return [];
  }
  return ["/careers", "/jobs", "/join", "/careers/"].map((path) => origin + path);
}

function timeoutSignal(ms: number): AbortSignal | undefined {
  if (typeof AbortSignal !== "undefined" && typeof AbortSignal.timeout === "function") {
    return AbortSignal.timeout(ms);
  }
  return undefined;
}

async function reachable(
  url: string,
  fetcher: FetchLike,
  timeoutMs: number
): Promise<boolean> {
  const init: RequestInit = {
    method: "GET",
    redirect: "follow",
    signal: timeoutSignal(timeoutMs),
    headers: { "user-agent": "hn-jobs/0.1 (+https://github.com)" },
  };
  const res = await fetcher(url, init);
  if (!(res.ok || (res.status >= 200 && res.status < 400))) return false;
  if (!res.text) return true;
  const body = (await res.text()).slice(0, 120000);
  return /\b(careers?|jobs?|open roles?|open positions?|join our team|we'?re hiring|work with us|apply now|greenhouse|lever|ashby|workable)\b/i.test(
    body
  );
}

export async function discoverCareersUrl(
  websiteUrl: string | null,
  options: { fetcher?: FetchLike; timeoutMs?: number } = {}
): Promise<{ url: string | null; status: EnrichmentStatus; notes: string | null }> {
  const candidates = candidateCareersUrls(websiteUrl);
  if (candidates.length === 0) {
    return { url: null, status: "skipped", notes: "no website url" };
  }

  const fetcher = options.fetcher ?? fetch;
  const timeoutMs = options.timeoutMs ?? 1500;
  try {
    for (const url of candidates) {
      if (await reachable(url, fetcher, timeoutMs)) {
        return { url, status: "enriched", notes: "careers page discovered" };
      }
    }
    return { url: null, status: "missed", notes: "common careers paths not found" };
  } catch (e) {
    return { url: null, status: "failed", notes: String(e).slice(0, 160) };
  }
}

export function initialEnrichmentData(input: ApplyLinkInput) {
  let enrichmentStatus: EnrichmentStatus = "pending";
  let enrichmentNotes: string | null = "ready for careers-page discovery";
  if (input.applyUrl) {
    enrichmentStatus = "skipped";
    enrichmentNotes = "apply link already parsed";
  } else if (!input.websiteUrl) {
    enrichmentStatus = "skipped";
    enrichmentNotes = "no website url";
  }

  return {
    enrichmentStatus,
    enrichmentVersion: ENRICHMENT_VERSION,
    enrichmentNotes,
    enrichedAt: null,
  };
}

export async function enrichApplyLink(
  input: ApplyLinkInput,
  options: { fetcher?: FetchLike; timeoutMs?: number } = {}
): Promise<ApplyLinkEnrichment> {
  if (input.applyUrl) {
    return {
      applyMethod: input.applyMethod,
      applyUrl: input.applyUrl,
      applyEmail: input.applyEmail,
      enrichmentStatus: "skipped",
      enrichmentVersion: ENRICHMENT_VERSION,
      enrichmentNotes: "apply link already parsed",
      enrichedAt: null,
    };
  }

  const discovered = await discoverCareersUrl(input.websiteUrl, options);
  if (discovered.url) {
    return {
      applyMethod: "link",
      applyUrl: discovered.url,
      applyEmail: input.applyEmail,
      enrichmentStatus: "enriched",
      enrichmentVersion: ENRICHMENT_VERSION,
      enrichmentNotes: discovered.notes,
      enrichedAt: new Date(),
    };
  }

  return {
    applyMethod: input.applyMethod,
    applyUrl: input.applyUrl,
    applyEmail: input.applyEmail,
    enrichmentStatus: discovered.status,
    enrichmentVersion: ENRICHMENT_VERSION,
    enrichmentNotes: discovered.notes,
    enrichedAt: new Date(),
  };
}

