test("discovers the first reachable careers page", async () => {
  const seen: string[] = [];
  const found = await discoverCareersUrl("https://acme.com", {
    fetcher: async (url) => {
      seen.push(url);
      return {
        ok: url.endsWith("/jobs"),
        status: url.endsWith("/jobs") ? 200 : 404,
        text: async () => "Open roles. Join our team.",
      };
    },
  });

  assert.equal(found.url, "https://acme.com/jobs");
  assert.equal(found.status, "enriched");
  assert.deepEqual(seen, ["https://acme.com/careers", "https://acme.com/jobs"]);
})

test("does not enrich generic SPA fallback pages", async () => {
  const result = await discoverCareersUrl("https://acme.com", {
    fetcher: async () => ({ ok: true, status: 200, text: async () => "Welcome to Acme." }),
  });

  assert.equal(result.url, null);
  assert.equal(result.status, "missed");
})

