// Stage 1 of the ingest pipeline: pure I/O against the public HN APIs.
// No parsing opinions here — just fetch JSON and strip HTML to text.
//
// We use two endpoints:
//   - Algolia search   https://hn.algolia.com/api/v1/search        (find threads)
//   - HN Firebase-ish   https://hn.algolia.com/api/v1/items/{id}    (thread + comments)
// Both are public, unauthenticated, and CORS-open.

const ALGOLIA = "https://hn.algolia.com/api/v1";

export interface HiringThread {
  hnId: string;
  title: string;
  postedAt: Date;
  numComments: number;
}

export interface RawComment {
  hnCommentId: string;
  author: string;
  postedAt: Date;
  rawHtml: string;
}

interface HiringThreadCandidate {
  month: string;
  thread: HiringThread;
}

const MONTHS: Record<string, string> = {
  january: "01",
  february: "02",
  march: "03",
  april: "04",
  may: "05",
  june: "06",
  july: "07",
  august: "08",
  september: "09",
  october: "10",
  november: "11",
  december: "12",
};

const HIRING_THREAD_QUERIES = ["Who is hiring", "Who's Hiring"];
const MONTH_NAME_PATTERN =
  "January|February|March|April|May|June|July|August|September|October|November|December";

async function getJson(url: string): Promise<any> {
  const maxAttempts = 4;
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    const res = await fetch(url, {
      headers: { "user-agent": "hn-jobs/0.1 (+https://github.com)" },
      // Don't cache during ingest; we want fresh thread state.
      cache: "no-store",
    });
    if (res.ok) return res.json();
    if (res.status === 429 && attempt < maxAttempts) {
      const retryAfter = res.headers.get("retry-after");
      const wait = retryAfter
        ? parseInt(retryAfter, 10) * 1000
        : 2000 * 2 ** (attempt - 1); // 2s, 4s, 8s
      console.warn(`HN API 429, attempt ${attempt}/${maxAttempts}, waiting ${wait}ms`);
      await new Promise((r) => setTimeout(r, wait));
      continue;
    }
    throw new Error(`HN API ${res.status} for ${url}`);
  }
  // Unreachable, but TS needs it.
  throw new Error(`HN API exhausted retries for ${url}`);
}

export function monthlyHiringThreadMonth(title: string): string | null {
  const match = title.trim().match(
    new RegExp(
      `^Ask HN:\\s*(?:Who is Hiring|Who's Hiring)\\?\\s*\\((${MONTH_NAME_PATTERN})\\s+(\\d{4})(?:\\s+Edition)?\\)$`,
      "i"
    )
  );
  if (!match) return null;
  const month = MONTHS[match[1].toLowerCase()];
  return month ? `${match[2]}-${month}` : null;
}

export function canonicalThreadIdFromText(text: string | null | undefined): string | null {
  if (!text || !/canonical post/i.test(text)) return null;
  const match = text.match(/item\?id=(\d+)/i);
  return match ? match[1] : null;
}

function threadFromItem(item: any): HiringThread | null {
  if (!item || typeof item.title !== "string") return null;
  if (!monthlyHiringThreadMonth(item.title)) return null;
  const createdAt = Number(item.created_at_i ?? 0);
  if (!createdAt) return null;
  return {
    hnId: String(item.id ?? item.objectID),
    title: String(item.title),
    postedAt: new Date(createdAt * 1000),
    numComments: Array.isArray(item.children) ? item.children.length : Number(item.num_comments ?? 0),
  };
}

async function threadFromSearchHit(hit: any): Promise<HiringThreadCandidate | null> {
  if (!hit || typeof hit.title !== "string") return null;
  const month = monthlyHiringThreadMonth(hit.title);
  if (!month) return null;

  const canonicalId = canonicalThreadIdFromText(hit.story_text);
  if (canonicalId) {
    const canonical = await getJson(`${ALGOLIA}/items/${canonicalId}`);
    const canonicalThread = threadFromItem(canonical);
    if (!canonicalThread) return null;
    const canonicalMonth =
      monthlyHiringThreadMonth(canonicalThread.title) ?? monthKey(canonicalThread.postedAt);
    return canonicalMonth === month ? { month, thread: canonicalThread } : null;
  }

  const createdAt = Number(hit.created_at_i ?? 0);
  if (!createdAt) return null;
  return {
    month,
    thread: {
      hnId: String(hit.objectID),
      title: String(hit.title),
      postedAt: new Date(createdAt * 1000),
      numComments: Number(hit.num_comments ?? 0),
    },
  };
}

function betterThreadCandidate(next: HiringThread, current: HiringThread): HiringThread {
  if (next.numComments !== current.numComments) {
    return next.numComments > current.numComments ? next : current;
  }
  return next.postedAt < current.postedAt ? next : current;
}

// Find the most recent monthly "Who is hiring?" job threads, newest first.
// Search story titles broadly instead of relying on a single bot author:
// early months and a few 2015 posts were submitted by other accounts.
// The exact title validator below filters out setup/meta posts and side
// threads, and we follow known canonical redirects such as December 2011. When
// multiple exact-title posts exist for a month, keep the highest-comment thread.
export async function findHiringThreads(limit = 6): Promise<HiringThread[]> {
  const target = Math.max(limit, 1);
  const hitsPerPage = 100;
  const bestByMonth = new Map<string, HiringThread>();
  let page = 0;
  let nbPages = 1;

  for (const query of HIRING_THREAD_QUERIES) {
    page = 0;
    nbPages = 1;
    while (page < nbPages) {
      const url =
        `${ALGOLIA}/search_by_date?tags=story` +
        `&query=${encodeURIComponent(query)}` +
        `&restrictSearchableAttributes=title&hitsPerPage=${hitsPerPage}&page=${page}`;
      const data = await getJson(url);
      const hits: any[] = Array.isArray(data?.hits) ? data.hits : [];
      nbPages = Number(data?.nbPages ?? 1) || 1;

      for (const hit of hits) {
        const candidate = await threadFromSearchHit(hit);
        if (!candidate) continue;
        const current = bestByMonth.get(candidate.month);
        bestByMonth.set(
          candidate.month,
          current ? betterThreadCandidate(candidate.thread, current) : candidate.thread
        );
      }
      page++;
    }
  }

  return Array.from(bestByMonth.entries())
    .sort(([a], [b]) => b.localeCompare(a))
    .map(([, thread]) => thread)
    .slice(0, target);
}

export async function findAllHiringThreads(): Promise<HiringThread[]> {
  return findHiringThreads(Number.MAX_SAFE_INTEGER);
}

// Fetch a thread and return its top-level comments (the job postings).
// Deleted/empty comments are dropped.
export async function fetchThreadComments(hnId: string): Promise<RawComment[]> {
  const data = await getJson(`${ALGOLIA}/items/${hnId}`);
  const children: any[] = Array.isArray(data?.children) ? data.children : [];
  const out: RawComment[] = [];
  for (const c of children) {
    if (!c || c.type !== "comment") continue;
    const text: unknown = c.text;
    if (typeof text !== "string" || text.trim().length === 0) continue;
    out.push({
      hnCommentId: String(c.id),
      author: String(c.author ?? "unknown"),
      postedAt: new Date(((c.created_at_i as number) ?? 0) * 1000),
      rawHtml: text,
    });
  }
  return out;
}

// Strip HN comment HTML to readable plain text.
// HN uses <p> for paragraph breaks, <a href> links, <i> italics, and HTML
// entities. We turn <p> into newlines and unescape the common entities.
export function htmlToText(html: string): string {
  return html
    .replace(/<p>/gi, "\n\n")
    .replace(/<\/p>/gi, "")
    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<a\b[^>]*>(.*?)<\/a>/gi, "$1")
    .replace(/<[^>]+>/g, "")
    .replace(/&#x2F;/g, "/")
    .replace(/&#x27;/g, "'")
    .replace(/&quot;/g, '"')
    .replace(/&gt;/g, ">")
    .replace(/&lt;/g, "<")
    .replace(/&amp;/g, "&")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

// Pull the first external (non-HN) URL out of a comment's HTML.
export function firstExternalUrl(html: string): string | null {
  const re = /href="([^"]+)"/gi;
  let m: RegExpExecArray | null;
  while ((m = re.exec(html))) {
    const href = m[1].replace(/&#x2F;/g, "/").replace(/&amp;/g, "&");
    if (/^https?:\/\//i.test(href) && !/news\.ycombinator\.com/i.test(href)) {
      return href;
    }
  }
  return null;
}

// "2026-05" from a Date. Thread.month prefers the title month; this is a fallback.
export function monthKey(d: Date): string {
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, "0");
  return `${y}-${m}`;
}

