// Stage 3 of the ingest pipeline: orchestration.
//
// Mirrors lib/crawler/index.ts in Lab Index. Fetch a thread's comments, parse
// each into structured fields, and upsert by hnCommentId. Idempotent: running
// it again refreshes the parse and the thread's cached job count without
// duplicating rows or touching the stored raw HTML.

import { prisma } from "../db";
import {
  findAllHiringThreads,
  findHiringThreads,
  fetchThreadComments,
  htmlToText,
  monthKey,
  monthlyHiringThreadMonth,
  type HiringThread,
} from "./fetch";
import { deriveJobCache } from "./derive";

export interface IngestResult {
  hnId: string;
  month: string;
  title: string;
  inserted: number;
  updated: number;
  total: number;
}

// Ingest one thread (by HN story id). Upserts the Thread row, then every
// top-level comment as a Job.
export async function ingestThread(thread: HiringThread): Promise<IngestResult> {
  const month = monthlyHiringThreadMonth(thread.title) ?? monthKey(thread.postedAt);

  const threadRow = await prisma.thread.upsert({
    where: { hnId: thread.hnId },
    create: {
      hnId: thread.hnId,
      month,
      title: thread.title,
      postedAt: thread.postedAt,
    },
    update: {
      title: thread.title,
      postedAt: thread.postedAt,
      month,
    },
  });

  const comments = await fetchThreadComments(thread.hnId);
  let inserted = 0;
  let updated = 0;

  for (const c of comments) {
    const rawText = htmlToText(c.rawHtml);

    const existing = await prisma.job.findUnique({
      where: { hnCommentId: c.hnCommentId },
      select: { id: true, llmEnriched: true },
    });

    const createData = {
      author: c.author,
      postedAt: c.postedAt,
      hnUrl: `https://news.ycombinator.com/item?id=${c.hnCommentId}`,
      rawHtml: c.rawHtml,
      rawText,
      ...deriveJobCache(rawText, c.rawHtml, { author: c.author }),
    };

    // Never touch raw snapshot fields or admin state on update.
    const { rawHtml: _rawHtml, rawText: _rawText, ...updateData } = createData;

    if (existing?.llmEnriched) {
      // Only update thread relation and non-derived fields; don't overwrite LLM data.
      await prisma.job.update({
        where: { hnCommentId: c.hnCommentId },
        data: { threadId: threadRow.id, author: c.author, postedAt: c.postedAt, hnUrl: `https://news.ycombinator.com/item?id=${c.hnCommentId}` },
      });
      updated++;
    } else {
      await prisma.job.upsert({
        where: { hnCommentId: c.hnCommentId },
        create: { hnCommentId: c.hnCommentId, threadId: threadRow.id, ...createData },
        update: updateData,
      });
      if (existing) updated++;
      else inserted++;
    }
  }

  const total = await prisma.job.count({ where: { threadId: threadRow.id } });
  await prisma.thread.update({
    where: { id: threadRow.id },
    data: { jobCount: total, lastIngestedAt: new Date() },
  });

  return { hnId: thread.hnId, month, title: thread.title, inserted, updated, total };
}

// Ingest the latest N hiring threads (default 1 — just the newest month).
export async function ingestLatest(count = 1): Promise<IngestResult[]> {
  const threads = await findHiringThreads(Math.max(count, 1));
  const results: IngestResult[] = [];
  for (const t of threads.slice(0, count)) {
    results.push(await ingestThread(t));
  }
  return results;
}

export async function ingestAllHiringThreads(): Promise<IngestResult[]> {
  const threads = await findAllHiringThreads();
  const results: IngestResult[] = [];
  for (const t of threads) {
    results.push(await ingestThread(t));
  }
  return results;
}

