// Post-ingest LLM enrichment pass. Runs after ingestThread to fill in gaps
// that the heuristic regex parser missed.
//
// Targets ALL posts in a thread (not just raw-only/partial), so fields the
// heuristic misses — salary, seniority, employment type, tech tags — get a
// chance to be filled by the LLM. The mergeWithHeuristic function ensures
// the heuristic parser's values win when present; the LLM only fills nulls.
//
// Uses Gemini via llm-parse.ts to extract company, role, location, salary,
// apply links, and tech tags from freeform post text. Also de-obfuscates
// emails ("name at example dot com" → "name@example.com").
//
// NEVER runs on posts that already have llmEnriched = true (guarded by
// ingestThread's update exclusion), so each post gets one LLM pass total.

import { prisma } from "../db";
import { parseJob } from "./parse";
import { llmParseJob, type LLMParseResult } from "./llm-parse";

export interface LLMEnrichResult {
  scanned: number;
  enriched: number;
  failed: number;
}

// Normalize salary values: if min is tiny and max is ≥100× larger, assume
// the LLM dropped "000" on the min side (common with "120k–180k" ranges).
function normalizeSalary(min: number | null, max: number | null): { salaryMin: number | null; salaryMax: number | null } {
  if (min != null && max != null && min < 1000 && max >= 100000) {
    return { salaryMin: min * 1000, salaryMax: max };
  }
  return { salaryMin: min, salaryMax: max };
}

// Build a partial update object from LLM result + heuristic, keeping heuristic
// values where the regex parser succeeded.
function buildUpdate(llm: LLMParseResult): Record<string, unknown> {
  const { salaryMin, salaryMax } = normalizeSalary(llm.salaryMin, llm.salaryMax);
  return {
    company: llm.company,
    role: llm.role ?? (llm.roles.length > 0 ? llm.roles[0] : null),
    roles: JSON.stringify(llm.roles),
    employmentType: llm.employmentType,
    remote: llm.remote,
    onsite: llm.onsite,
    hybrid: llm.hybrid,
    locationDisplay: llm.locations.length > 0 ? llm.locations.join(", ") : null,
    locations: JSON.stringify(llm.locations),
    remoteScope: llm.remoteScope,
    visa: llm.visa,
    intern: llm.intern,
    salaryMin,
    salaryMax,
    salaryCurrency: llm.salaryCurrency,
    salaryPeriod: llm.salaryPeriod,
    equity: llm.equity,
    applyUrl: llm.applyUrl,
    applyEmail: llm.applyEmail,
    tags: JSON.stringify(llm.tags),
    parseConfidence: "parsed",
    llmEnriched: true,
  };
}

// Run LLM enrichment on all posts in a thread that aren't yet enriched. Skips
// posts that already have llmEnriched = true.
export async function llmEnrichThread(threadId: number): Promise<LLMEnrichResult> {
  const jobs = await prisma.job.findMany({
    where: {
      threadId,
      llmEnriched: false,
      hidden: false,
    },
    select: { id: true, rawText: true, rawHtml: true, author: true },
  });

  if (jobs.length === 0) {
    return { scanned: 0, enriched: 0, failed: 0 };
  }

  console.log(`LLM enrich: scanning ${jobs.length} posts in thread ${threadId}`);

  let enriched = 0;
  let failed = 0;

  for (const [i, job] of jobs.entries()) {
    // Pace requests — free tier is ~10 req/min (6s) but bursts of a few are
    // OK before the daily cap kicks in. 200ms is enough to avoid tripping
    // per-second rate limits during a small daily batch.
    if (i > 0) await new Promise((r) => setTimeout(r, 200));

    const heuristic = parseJob(job.rawText, job.rawHtml, { author: job.author });
    const llmResult = await llmParseJob(job.rawText, heuristic);
    if (!llmResult) {
      failed++;
      continue;
    }

    const updateData = buildUpdate(llmResult);
    await prisma.job.update({ where: { id: job.id }, data: updateData });
    enriched++;
  }

  console.log(`LLM enrich: ${enriched} enriched, ${failed} failed`);
  return { scanned: jobs.length, enriched, failed };
}

