// LLM-assisted extraction for low-confidence HN job postings.
//
// Only called for `partial` and `raw-only` posts where the heuristic parser
// couldn't find a clean header. Uses Gemini Flash with JSON response schema
// so the result is always typed — never free text to re-parse.
//
// The heuristic parse result is passed in so the LLM only fills gaps,
// not re-derive everything from scratch.

import { GoogleGenerativeAI, SchemaType } from "@google/generative-ai";
import type { ParsedJob } from "./parse";

let _model: ReturnType<GoogleGenerativeAI["getGenerativeModel"]> | null = null;

function getModel() {
  if (_model) return _model;
  if (!process.env.GEMINI_API_KEY) {
    throw new Error("GEMINI_API_KEY is not set — cannot run LLM enrichment");
  }
  const genAI = new GoogleGenerativeAI(process.env.GEMINI_API_KEY);
  _model = genAI.getGenerativeModel({
    model: "gemini-2.0-flash",
    generationConfig: {
      responseMimeType: "application/json",
      responseSchema: {
        type: SchemaType.OBJECT,
        properties: {
          company: { type: SchemaType.STRING },
          role: { type: SchemaType.STRING },
          roles: { type: SchemaType.ARRAY, items: { type: SchemaType.STRING } },
          employment_type: { type: SchemaType.STRING },
          remote: { type: SchemaType.BOOLEAN },
          onsite: { type: SchemaType.BOOLEAN },
          hybrid: { type: SchemaType.BOOLEAN },
          locations: { type: SchemaType.ARRAY, items: { type: SchemaType.STRING } },
          remote_scope: { type: SchemaType.STRING },
          visa: { type: SchemaType.BOOLEAN },
          intern: { type: SchemaType.BOOLEAN },
          salary_min: { type: SchemaType.NUMBER },
          salary_max: { type: SchemaType.NUMBER },
          salary_currency: { type: SchemaType.STRING },
          salary_period: { type: SchemaType.STRING },
          equity: { type: SchemaType.BOOLEAN },
          apply_url: { type: SchemaType.STRING },
          apply_email: { type: SchemaType.STRING },
          tags: { type: SchemaType.ARRAY, items: { type: SchemaType.STRING } },
        },
      },
    },
  });
  return _model;
}

export interface LLMParseResult {
  company: string | null;
  role: string | null;
  roles: string[];
  employmentType: string | null;
  remote: boolean;
  onsite: boolean;
  hybrid: boolean;
  locations: string[];
  remoteScope: string | null;
  visa: boolean;
  intern: boolean;
  salaryMin: number | null;
  salaryMax: number | null;
  salaryCurrency: string | null;
  salaryPeriod: string | null;
  equity: boolean;
  applyUrl: string | null;
  applyEmail: string | null;
  tags: string[];
}

// Merge heuristic parse + LLM result. Heuristic values win when present.
export function mergeWithHeuristic(
  heuristic: ParsedJob,
  llm: LLMParseResult
): LLMParseResult {
  return {
    company: heuristic.company ?? llm.company,
    role: heuristic.role ?? llm.role,
    roles: heuristic.roles.length > 0 ? heuristic.roles : llm.roles,
    employmentType: heuristic.employmentType ?? llm.employmentType,
    remote: heuristic.remote || llm.remote,
    onsite: heuristic.onsite || llm.onsite,
    hybrid: heuristic.hybrid || llm.hybrid,
    locations:
      heuristic.location.places.length > 0 ? heuristic.location.places : llm.locations,
    remoteScope: heuristic.location.remoteScope ?? llm.remoteScope,
    visa: heuristic.visa || llm.visa,
    intern: heuristic.intern || llm.intern,
    salaryMin: heuristic.salary.min ?? llm.salaryMin,
    salaryMax: heuristic.salary.max ?? llm.salaryMax,
    salaryCurrency: heuristic.salary.currency ?? llm.salaryCurrency,
    salaryPeriod: heuristic.salary.period ?? llm.salaryPeriod,
    equity: heuristic.salary.equity || llm.equity,
    applyUrl: heuristic.apply.url ?? llm.applyUrl,
    applyEmail: heuristic.apply.email ?? llm.applyEmail,
    tags: [...new Set([...heuristic.tags, ...llm.tags])],
  };
}

function asString(v: unknown): string | null {
  return typeof v === "string" && v.length > 0 ? v : null;
}

function asStringArray(v: unknown): string[] {
  return Array.isArray(v) ? v.filter((e): e is string => typeof e === "string") : [];
}

function asBool(v: unknown): boolean {
  return v === true;
}

function asNumber(v: unknown): number | null {
  return typeof v === "number" && Number.isFinite(v) ? v : null;
}

export async function llmParseJob(
  rawText: string,
  heuristic: ParsedJob
): Promise<LLMParseResult | null> {
  // Truncate to avoid blowing context — first 4000 chars covers the header,
  // body, salary, location, and contact info for most postings.
  const text = rawText.slice(0, 4000);

  const prompt = `Extract structured fields from this HN "Who is hiring?" job posting. Only extract what is explicitly stated — do not infer or hallucinate. For boolean fields not mentioned, return false. For string/number fields not mentioned, omit them.\n\n${text}`;

  // Retry on 429 with exponential backoff — free tier is ~10 req/min, so the
  // backfill will periodically trip the limit. Honor the server's retryDelay
  // when present, otherwise back off 5s, 10s, 20s.
  const maxAttempts = 4;
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const result = await getModel().generateContent(prompt);
      const raw = JSON.parse(result.response.text()) as Record<string, unknown>;

      const llm: LLMParseResult = {
        company: asString(raw.company),
        role: asString(raw.role),
        roles: asStringArray(raw.roles),
        employmentType: asString(raw.employment_type),
        remote: asBool(raw.remote),
        onsite: asBool(raw.onsite),
        hybrid: asBool(raw.hybrid),
        locations: asStringArray(raw.locations),
        remoteScope: asString(raw.remote_scope),
        visa: asBool(raw.visa),
        intern: asBool(raw.intern),
        salaryMin: asNumber(raw.salary_min),
        salaryMax: asNumber(raw.salary_max),
        salaryCurrency: asString(raw.salary_currency),
        salaryPeriod: asString(raw.salary_period),
        equity: asBool(raw.equity),
        applyUrl: asString(raw.apply_url),
        applyEmail: asString(raw.apply_email),
        tags: asStringArray(raw.tags),
      };

      return mergeWithHeuristic(heuristic, llm);
    } catch (err) {
      const status = (err as { status?: number })?.status;
      if (status === 429 && attempt < maxAttempts) {
        const wait = 5000 * 2 ** (attempt - 1); // 5s, 10s, 20s
        await new Promise((r) => setTimeout(r, wait));
        continue;
      }
      console.error("LLM parse error:", err);
      return null;
    }
  }

  return null;
}

