test("de-obfuscates angle-bracket email forms", () => {
  const parsed = parseJob(
    "Acme | Backend Engineer | Remote\nEmail recruiting <at> acme <dot> com"
  );

  assert.equal(parsed.apply.method, "email");
  assert.equal(parsed.apply.email, "recruiting@acme.com");
  assert.equal(parsed.website, "https://acme.com");
})

test("prefers direct emails before de-obfuscating surrounding prose", () => {
  const parsed = parseJob(
    "Acme | Backend Engineer | Remote\nPlease reach out at liz.woodfield@example.com."
  );

  assert.equal(parsed.apply.email, "liz.woodfield@example.com");
})

test("infers placeholder email local parts from first-person intro names", () => {
  const parsed = parseJob(
    "9 Mothers YC P26 | Robotics | Austin, ONSITE | 9mothers.com\n\n" +
      "I'm Roman, co-founder of 9 Mothers. Reach out to me directly at (name)@9mothers.com."
  );

  assert.equal(parsed.apply.email, "roman@9mothers.com");
})

test("infers HN username email placeholders from the comment author", () => {
  const parsed = parseJob(
    "New Lantern | Backend Engineer | SF\n" +
      "I'm Steve, Head of Engineering. Shoot me a note at (my HN username)@newlantern.ai.",
    undefined,
    { author: "woodrow" }
  );

  assert.equal(parsed.apply.email, "woodrow@newlantern.ai");
})

test("does not keep obvious placeholder email local parts without a contact name", () => {
  const parsed = parseJob(
    "Acme | Backend Engineer | Remote\nEmail name@acme.com with your resume."
  );

  assert.equal(parsed.apply.email, null);
})

test("keeps bare first@ aliases as real email addresses", () => {
  const parsed = parseJob(
    "Streak.com | Engineers | San Francisco\nEmail us at first@streak.com if you are interested."
  );

  assert.equal(parsed.apply.email, "first@streak.com");
})

test("treats bare careers domains as application links", () => {
  const parsed = parseJob("Acme | Backend Engineer | Remote | acme.com/careers");

  assert.equal(parsed.website, "https://acme.com");
  assert.equal(parsed.apply.method, "link");
  assert.equal(parsed.apply.url, "https://acme.com/careers");
})

test("treats bare jobs subdomains as application links", () => {
  const parsed = parseJob("Acme | Backend Engineer | Remote | jobs.acme.com");

  assert.equal(parsed.website, "https://acme.com");
  assert.equal(parsed.apply.method, "link");
  assert.equal(parsed.apply.url, "https://jobs.acme.com");
})

test("does not treat non-job prose as a company", () => {
  const parsed = parseJob("Estoy disponible cuando quieras!!!");

  assert.equal(parsed.company, null);
  assert.equal(parsed.parseConfidence, "raw-only");
})

test("does not use author fallback data as parsed company", () => {
  const parsed = parseJob(
    "I am looking for someone who can help us build the ecosystem or an affiliate program for www.commudle.com in the USA. Can reach out directly to me at arpan[at]commudle[dot]com."
  );

  assert.equal(parsed.company, "Commudle");
  assert.equal(parsed.website, "https://commudle.com");
  assert.equal(parsed.apply.email, "arpan@commudle.com");
})

test("extracts company names from prose introductions", () => {
  const parsed = parseJob(
    "SwingVision is the AI tennis & pickleball app that provides automated stats.\n\nOpen roles:\n- Data Labeling Intern"
  );

  assert.equal(parsed.company, "SwingVision");
  assert.equal(parsed.role, "Data Labeling Intern");
})

test("preserves compact company-only headers", () => {
  const parsed = parseJob("This Dot Labs");

  assert.equal(parsed.company, "This Dot Labs");
  assert.equal(parsed.parseConfidence, "partial");
})

test("does not turn prose introductions into roles", () => {
  const parsed = parseJob(
    "Hey HN! Air Space Intelligence (https://www.airspace-intelligence.com) is hiring. We are a frontier AI and product company for critical industries."
  );

  assert.equal(parsed.company, "Airspace Intelligence");
  assert.equal(parsed.role, null);
  assert.equal(parsed.parseConfidence, "partial");
})

test("strips leading markdown bullets from company headers", () => {
  const parsed = parseJob("*Scribd | Lead Product Manager | Remote");

  assert.equal(parsed.company, "Scribd");
  assert.equal(parsed.role, "Lead Product Manager");
})

