// Adaptive ingest scheduler for the Fly cron endpoint.
//
// The Fly cron hits us every 15 minutes. This module decides what to do:
//
//   Phase 0 — No current-month thread yet (end-of-month watch)
//     → ask HN Algolia for the latest hiring thread
//     → if it's the expected month, ingest it
//     → this handles the ~1st-of-month new-thread event
//
//   Phase 1 — Fresh thread, first 48 hours (spike)
//     → ingest every ~15 min (every cron tick)
//
//   Phase 2 — Maturing thread, days 2-5
//     → ingest every ~2 hours
//
//   Phase 3 — Settled thread, after day 5
//     → ingest every ~6 hours
//
// All thresholds are derived from Thread.postedAt and lastIngestedAt;
// no extra state is needed.

import { prisma } from "../db";
import { findHiringThreads, monthlyHiringThreadMonth, type HiringThread } from "./fetch";
import { ingestThread, type IngestResult } from "./ingest";

export interface CronResult {
  action: "skip" | "ingest" | "ingest-new-thread";
  reason?: string;
  ingestResult?: IngestResult;
}

const FIFTEEN_MIN = 0.25;
const TWO_HOURS = 2;
const SIX_HOURS = 6;

function monthKey(d: Date): string {
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, "0");
  return `${y}-${m}`;
}

function threadMonth(t: HiringThread): string {
  return monthlyHiringThreadMonth(t.title) ?? monthKey(t.postedAt);
}

export async function runScheduledIngest(now: Date = new Date()): Promise<CronResult> {
  const expectedMonth = monthKey(now);

  const newest = await prisma.thread.findFirst({
    orderBy: { month: "desc" },
    select: { hnId: true, month: true, postedAt: true, lastIngestedAt: true },
  });

  // No thread for the expected month → check HN for a new one.
  if (!newest || newest.month !== expectedMonth) {
    const threads = await findHiringThreads(1);
    if (threads.length === 0) {
      return { action: "skip", reason: "no hiring threads found on HN" };
    }
    const latest = threads[0];
    if (threadMonth(latest) !== expectedMonth) {
      return {
        action: "skip",
        reason: `latest HN thread is ${threadMonth(latest)}, not ${expectedMonth} yet`,
      };
    }
    const ingestResult = await ingestThread(latest);
    return { action: "ingest-new-thread", ingestResult };
  }

  // We have the current month's thread — decide ingest frequency.
  const ageHours = (now.getTime() - newest.postedAt.getTime()) / 3_600_000;
  const lastIngest = newest.lastIngestedAt ?? new Date(0);
  const hoursSinceIngest = (now.getTime() - lastIngest.getTime()) / 3_600_000;

  if (ageHours < 48) {
    if (hoursSinceIngest < FIFTEEN_MIN) {
      return { action: "skip", reason: "spike — ingested recently" };
    }
  } else if (ageHours < 120) {
    if (hoursSinceIngest < TWO_HOURS) {
      return { action: "skip", reason: "maturing — ingested <2h ago" };
    }
  } else {
    if (hoursSinceIngest < SIX_HOURS) {
      return { action: "skip", reason: "settled — ingested <6h ago" };
    }
  }

  // Time to ingest. Find the thread on HN by its hnId.
  const threads = await findHiringThreads(1);
  const thread = threads.find((t) => t.hnId === newest.hnId);
  if (!thread) {
    return { action: "skip", reason: `thread ${newest.hnId} not found on HN` };
  }
  const ingestResult = await ingestThread(thread);
  return { action: "ingest", ingestResult };
}

