test("uses internship and salary disclosure as derived facets", () => {
  const result = classifyJobTaxonomy({
    role: "Software Engineering Intern",
    roles: ["Software Engineering Intern"],
    rawText: "Software Engineering Intern | Remote | $40/hr",
    tags: [],
    employmentType: "internship",
    parseConfidence: "parsed",
    intern: true,
    salaryMin: 40,
    salaryMax: 40,
  });

  assert.equal(result.seniority, "Intern");
  assert.equal(result.salaryBucket, "disclosed");
  assert.equal(result.needsReview, false);
})

test("falls back to header-like raw text when the parsed role is missing", () => {
  const result = classifyJobTaxonomy({
    role: null,
    roles: [],
    rawText: "Ashby | Hiring Senior/Staff Product Engineers (Americas) | Remote | Full-time",
    tags: [],
    employmentType: "full-time",
    parseConfidence: "parsed",
    intern: false,
    salaryMin: null,
    salaryMax: null,
  });

  assert.deepEqual(result.roleFamilies, ["Full-stack / Product Engineering"]);
  assert.equal(result.seniority, "Staff / Principal");
  assert.equal(result.classificationConfidence, "medium");
  assert.equal(result.needsReview, false);
})

