import { formatCompanyName, parseJsonArray } from "@/lib/format";

export type JobSort = "company" | "newest" | "salary-desc";
export type ApplyFilter = "link" | "email" | "hn-reply" | "missing";

export interface JobFilters {
  q: string;
  tag?: string;
  family?: string;
  seniority?: string;
  salary?: string;
  region?: string;
  apply?: ApplyFilter;
  remote: boolean;
  visa: boolean;
  intern: boolean;
  sort: JobSort;
}

export interface JobFilterable {
  company: string | null;
  role: string | null;
  rawText: string;
  author: string;
  locationDisplay: string | null;
  locationRegions: string;
  websiteUrl: string | null;
  tags: string;
  roleFamilies: string;
  seniority: string | null;
  salaryBucket: string | null;
  salaryMin: number | null;
  salaryMax: number | null;
  applyMethod: string;
  applyUrl: string | null;
  applyEmail: string | null;
  remote: boolean;
  visa: boolean;
  intern: boolean;
  postedAt: Date;
}

type SearchParamObject = Record<string, string | string[] | undefined>;
type SearchParamSource = URLSearchParams | SearchParamObject;

function param(source: SearchParamSource, key: string): string | undefined {
  if (source instanceof URLSearchParams) return source.get(key) ?? undefined;
  const value = source[key];
  return Array.isArray(value) ? value[0] : value;
}

function validSort(value: string | undefined, fallback: JobSort): JobSort {
  return value === "company" || value === "newest" || value === "salary-desc" ? value : fallback;
}

function validApply(value: string | undefined): ApplyFilter | undefined {
  return value === "link" || value === "email" || value === "hn-reply" || value === "missing"
    ? value
    : undefined;
}

export function parseJobFilters(source: SearchParamSource, defaultSort: JobSort = "company"): JobFilters {
  return {
    q: (param(source, "q") ?? "").trim(),
    tag: param(source, "tag"),
    family: param(source, "family"),
    seniority: param(source, "seniority"),
    salary: param(source, "salary"),
    region: param(source, "region"),
    apply: validApply(param(source, "apply")),
    remote: param(source, "remote") === "1",
    visa: param(source, "visa") === "1",
    intern: param(source, "intern") === "1",
    sort: validSort(param(source, "sort"), defaultSort),
  };
}

export function applyFilterLabel(value: string): string | null {
  switch (value) {
    case "link": return "Application link";
    case "email": return "Email";
    case "hn-reply": return "HN reply";
    case "missing": return "Missing apply path";
    default: return null;
  }
}

export function applyBucketsForJob(job: Pick<JobFilterable, "applyMethod" | "applyUrl" | "applyEmail">): ApplyFilter[] {
  const buckets: ApplyFilter[] = [];
  if (job.applyUrl) buckets.push("link");
  if (job.applyEmail) buckets.push("email");
  if (job.applyMethod === "hn-reply") buckets.push("hn-reply");
  if (buckets.length === 0) buckets.push("missing");
  return buckets;
}

function isMeaningfulLocation(location: string | null): boolean {
  if (!location) return false;
  const clean = location.replace(/\s+/g, " ").trim().toLowerCase();
  if (!clean) return false;
  return !/^(?:remote(?:\s*\([^)]*\))?|on-?site|onsite|hybrid)$/.test(clean);
}

function hasSubstantiveRawText(rawText: string): boolean {
  const clean = rawText.replace(/\s+/g, " ").trim();
  if (!clean) return false;
  if (/^(?:\[flagged\]|remote|n\/a|na|none|nope|test)$/i.test(clean)) return false;
  const words = clean.match(/[a-z0-9][a-z0-9.+#'-]*/gi) ?? [];
  return clean.length >= 80 && words.length >= 12;
}

export function hasPublicListingSignal(job: JobFilterable): boolean {
  if (formatCompanyName(job.company)) return true;
  if (job.role?.trim()) return true;
  if (job.websiteUrl) return true;
  if (job.applyUrl || job.applyEmail || job.applyMethod === "hn-reply") return true;
  if (job.salaryBucket === "disclosed" || job.salaryMin != null || job.salaryMax != null) return true;
  if (parseJsonArray(job.tags).length > 0) return true;
  if (parseJsonArray(job.roleFamilies).length > 0 || job.seniority) return true;
  if (isMeaningfulLocation(job.locationDisplay)) return true;
  return hasSubstantiveRawText(job.rawText);
}

export function jobMatchesFilters(job: JobFilterable, filters: JobFilters): boolean {
  if (!hasPublicListingSignal(job)) return false;
  if (filters.remote && !job.remote) return false;
  if (filters.visa && !job.visa) return false;
  if (filters.intern && !job.intern) return false;
  if (filters.tag && !parseJsonArray(job.tags).includes(filters.tag)) return false;
  if (filters.family && !parseJsonArray(job.roleFamilies).includes(filters.family)) return false;
  if (filters.seniority && job.seniority !== filters.seniority) return false;
  if (filters.region && !parseJsonArray(job.locationRegions).includes(filters.region)) return false;
  if (filters.apply && !applyBucketsForJob(job).includes(filters.apply)) return false;
  if (filters.salary === "disclosed" && job.salaryBucket !== "disclosed") return false;
  if (filters.salary === "undisclosed" && job.salaryBucket === "disclosed") return false;

  if (filters.q) {
    const hay = [
      job.company ?? "",
      job.role ?? "",
      job.locationDisplay ?? "",
      job.rawText,
      job.author,
      parseJsonArray(job.tags).join(" "),
    ].join(" ").toLowerCase();
    if (!hay.includes(filters.q.toLowerCase())) return false;
  }

  return true;
}

function salarySortValue(job: Pick<JobFilterable, "salaryMin" | "salaryMax">): number {
  return job.salaryMax ?? job.salaryMin ?? Number.NEGATIVE_INFINITY;
}

export function sortJobsForDirectory<T extends JobFilterable>(jobs: T[], sort: JobSort): T[] {
  return [...jobs].sort((a, b) => {
    if (sort === "salary-desc") {
      const bySalary = salarySortValue(b) - salarySortValue(a);
      if (bySalary !== 0) return bySalary;
    } else if (sort === "company") {
      const companyA = formatCompanyName(a.company) ?? "\uffff";
      const companyB = formatCompanyName(b.company) ?? "\uffff";
      const byCompany = companyA.localeCompare(companyB);
      if (byCompany !== 0) return byCompany;
    }
    return b.postedAt.getTime() - a.postedAt.getTime();
  });
}

