function param(source: SearchParamSource, key: string): string | undefined {
  if (source instanceof URLSearchParams) return source.get(key) ?? undefined;
  const value = source[key];
  return Array.isArray(value) ? value[0] : value;
}

function validSort(value: string | undefined, fallback: JobSort): JobSort {
  return value === "company" || value === "newest" || value === "salary-desc" ? value : fallback;
}

function validApply(value: string | undefined): ApplyFilter | undefined {
  return value === "link" || value === "email" || value === "hn-reply" || value === "missing"
    ? value
    : undefined;
}

export function parseJobFilters(source: SearchParamSource, defaultSort: JobSort = "company"): JobFilters {
  return {
    q: (param(source, "q") ?? "").trim(),
    tag: param(source, "tag"),
    family: param(source, "family"),
    seniority: param(source, "seniority"),
    salary: param(source, "salary"),
    region: param(source, "region"),
    apply: validApply(param(source, "apply")),
    remote: param(source, "remote") === "1",
    visa: param(source, "visa") === "1",
    intern: param(source, "intern") === "1",
    sort: validSort(param(source, "sort"), defaultSort),
  };
}

