import { NextRequest, NextResponse } from "next/server";

// AI training crawlers + high-volume scrapers. Legitimate search bots
// (Googlebot, Bingbot) are intentionally not listed.
const BLOCKED_BOT_PATTERNS = [
  "ccbot",
  "gptbot",
  "google-extended",
  "anthropic-ai",
  "claude-web",
  "cohere-ai",
  "perplexitybot",
  "bytespider",
  "ahrefsbot",
  "semrushbot",
  "mj12bot",
  "dotbot",
  "dataforseobot",
  "petalbot",
  "amazonbot",
  "applebot-extended",
  "facebookbot",
  "ia_archiver",
  "omgilibot",
  "omgili",
  "scrapy",
  "python-requests",
  "go-http-client/1",
];

// Ban IPs that trigger rate limits 3+ times in a rolling 30min window
const bans = new Map<string, { count: number; expiresAt: number }>();
const BAN_THRESHOLD = 3;
const BAN_DURATION_MS = 30 * 60_000;

// Per-route rate limit buckets
const limits = new Map<string, { count: number; windowStart: number }>();

type Bucket = { limit: number; windowMs: number };

const BUCKETS: Record<string, Bucket> = {
  // API – 20 req/min (feed readers, scrapers)
  "/api/": { limit: 20, windowMs: 60_000 },
  // RSS – 6 req/min (aggressive feed readers)
  "/api/rss": { limit: 6, windowMs: 60_000 },
  // Cron – 1 req/min (should only be called once per 15min)
  "/api/cron": { limit: 1, windowMs: 60_000 },
  // Login – 5 req/min
  "/login": { limit: 5, windowMs: 60_000 },
};

function getBucket(path: string): Bucket | undefined {
  if (path.startsWith("/api/rss")) return BUCKETS["/api/rss"];
  if (path.startsWith("/api/cron")) return BUCKETS["/api/cron"];
  if (path.startsWith("/api/")) return BUCKETS["/api/"];
  if (path.startsWith("/login")) return BUCKETS["/login"];
  return undefined;
}

function getIp(req: NextRequest): string {
  return (
    req.headers.get("x-forwarded-for")?.split(",")[0].trim() ??
    req.headers.get("x-real-ip") ??
    "unknown"
  );
}

function isBanned(ip: string): boolean {
  const ban = bans.get(ip);
  if (!ban) return false;
  if (Date.now() > ban.expiresAt) {
    bans.delete(ip);
    return false;
  }
  return true;
}

function recordViolation(ip: string) {
  const now = Date.now();
  const ban = bans.get(ip);
  if (ban && now < ban.expiresAt) {
    ban.count += 1;
  } else {
    bans.set(ip, { count: 1, expiresAt: now + BAN_DURATION_MS });
  }
  if (ban && ban.count >= BAN_THRESHOLD) {
    ban.expiresAt = now + BAN_DURATION_MS;
  }
  if (bans.size > 5000) {
    for (const [k, v] of bans) {
      if (now > v.expiresAt) bans.delete(k);
    }
  }
}

function checkBucket(ip: string, path: string, bucket: Bucket): { limited: boolean; remaining: number; windowStart: number } {
  const { limit, windowMs } = bucket;
  const key = `${path}:${ip}`;
  const now = Date.now();
  const entry = limits.get(key);

  if (!entry || now > entry.windowStart + windowMs) {
    limits.set(key, { count: 1, windowStart: now });
    return { limited: false, remaining: limit - 1, windowStart: now };
  }

  entry.count += 1;

  if (limits.size > 10000) {
    for (const [k, v] of limits) {
      if (now > v.windowStart + windowMs) limits.delete(k);
    }
  }

  return {
    limited: entry.count > limit,
    remaining: Math.max(0, limit - entry.count),
    windowStart: entry.windowStart,
  };
}

function limitResponse(windowStart: number, limit: number): NextResponse {
  const retryAfter = Math.ceil((windowStart + 60_000 - Date.now()) / 1000);
  return new NextResponse("Too Many Requests", {
    status: 429,
    headers: {
      "Retry-After": String(Math.max(1, retryAfter)),
      "X-RateLimit-Limit": String(limit),
      "X-RateLimit-Remaining": "0",
      "X-RateLimit-Reset": String(Math.ceil((windowStart + 60_000) / 1000)),
      "Content-Type": "text/plain",
    },
  });
}

export function middleware(req: NextRequest) {
  const { pathname, hostname } = req.nextUrl;

  // www → apex redirect
  if (hostname.startsWith("www.")) {
    const url = req.nextUrl.clone();
    url.hostname = hostname.slice(4);
    return NextResponse.redirect(url, 301);
  }

  const ua = (req.headers.get("user-agent") || "").toLowerCase();

  // Layer 1: known bad bots
  if (BLOCKED_BOT_PATTERNS.some((p) => ua.includes(p))) {
    return new NextResponse("Forbidden", {
      status: 403,
      headers: { "Content-Type": "text/plain" },
    });
  }

  // Rate limiting (bans + per-route buckets) applies only to protected
  // routes: API, RSS, cron, login. The main website (directory pages) is
  // never throttled or banned — casual browsing should never hit a 429.
  const bucket = getBucket(pathname);
  if (bucket) {
    const ip = getIp(req);

    // Layer 2: banned IPs (repeated 429 offenders on protected routes)
    if (isBanned(ip)) {
      return limitResponse(Date.now(), 0);
    }

    // Layer 3: per-route rate limit
    const { limited, remaining, windowStart } = checkBucket(ip, pathname, bucket);
    if (limited) {
      recordViolation(ip);
      return limitResponse(windowStart, bucket.limit);
    }

    const res = NextResponse.next();
    res.headers.set("X-RateLimit-Limit", String(bucket.limit));
    res.headers.set("X-RateLimit-Remaining", String(remaining));
    res.headers.set("X-RateLimit-Reset", String(Math.ceil((windowStart + bucket.windowMs) / 1000)));
    return res;
  }

  return NextResponse.next();
}

export const config = {
  matcher: [
    "/((?!_next/static|_next/data|_next/image|favicon.ico).*)",
  ],
};

