      "Content-Type": "text/plain",
    },
  });
}

export function middleware(req: NextRequest) {
  const { pathname, hostname } = req.nextUrl;

  // www → apex redirect
  if (hostname.startsWith("www.")) {
    const url = req.nextUrl.clone();
    url.hostname = hostname.slice(4);
    return NextResponse.redirect(url, 301);
  }

  const ua = (req.headers.get("user-agent") || "").toLowerCase();

  // Layer 1: known bad bots
  if (BLOCKED_BOT_PATTERNS.some((p) => ua.includes(p))) {
    return new NextResponse("Forbidden", {
      status: 403,
      headers: { "Content-Type": "text/plain" },
    });
  }

  // Rate limiting (bans + per-route buckets) applies only to protected
  // routes: API, RSS, cron, login. The main website (directory pages) is
  // never throttled or banned — casual browsing should never hit a 429.
  const bucket = getBucket(pathname);
  if (bucket) {
    const ip = getIp(req);

    // Layer 2: banned IPs (repeated 429 offenders on protected routes)
    if (isBanned(ip)) {
      return limitResponse(Date.now(), 0);
    }

    // Layer 3: per-route rate limit
    const { limited, remaining, windowStart } = checkBucket(ip, pathname, bucket);
    if (limited) {
      recordViolation(ip);
      return limitResponse(windowStart, bucket.limit);
    }

    const res = NextResponse.next();
    res.headers.set("X-RateLimit-Limit", String(bucket.limit));
    res.headers.set("X-RateLimit-Remaining", String(remaining));
    res.headers.set("X-RateLimit-Reset", String(Math.ceil((windowStart + bucket.windowMs) / 1000)));
    return res;
  }

  return NextResponse.next();
}

