// Idempotent seed. Unlike Lab Index (which has hand-curated editorial data),
// HN Jobs has no static seed — the "seed" is the latest live "Who is hiring?"
// thread pulled from HN. Re-running upserts by hnCommentId, so it's safe to run
// repeatedly. Pass HN_SEED_THREADS=3 to backfill more months.

import { ingestLatest } from "../lib/hn/ingest";

async function main() {
  const count = Number(process.env.HN_SEED_THREADS ?? 1) || 1;
  console.log(`Seeding from the latest ${count} HN "Who is hiring?" thread(s)…`);
  try {
    const results = await ingestLatest(count);
    if (results.length === 0) {
      console.warn(
        "No hiring threads returned from HN. The DB schema is ready; run `npm run ingest` later."
      );
    }
    for (const r of results) {
      console.log(`  ${r.month}: ${r.total} jobs ingested.`);
    }
  } catch (e) {
    // Don't fail `npm run setup` just because the network is down — the schema
    // is already pushed by that point. Surface the error and move on.
    console.warn("Seed ingest failed (network?). Schema is ready; run `npm run ingest` later.");
    console.warn(String(e));
  }
}

main().finally(() => process.exit(0));

