// Part 2 of the agent-driven backfill: apply Claude's hand-extracted fields
// back to the DB, running them through the same taxonomy classifier the live
// parser uses so derived columns don't drift.
//
// Input JSON is an array of objects, one per job:
//   { "id": 279, "company": "...", "role": "...", "roles": [...],
//     "employmentType": "full-time", "remote": true, "onsite": false,
//     "hybrid": false, "locations": ["NYC"], "remoteScope": "US",
//     "visa": false, "intern": false, "salaryMin": null, "salaryMax": null,
//     "salaryCurrency": null, "salaryPeriod": null, "equity": false,
//     "applyUrl": null, "applyEmail": null, "tags": ["React"] }
//
// To mark a comment that isn't a real job posting (job-seeker, noise, spam),
// set { "id": 302, "exclude": "not-a-job-post" } — it's hidden, not deleted.
//
// Usage: npm run backfill:apply -- --in /tmp/parsed.json

import { readFileSync } from "node:fs";
import { prisma } from "@/lib/db";
import { classifyJobTaxonomy, serializeJobTaxonomy } from "@/lib/hn/taxonomy";

interface Extraction {
  id: number;
  exclude?: string;
  company?: string | null;
  role?: string | null;
  roles?: string[];
  employmentType?: string | null;
  remote?: boolean;
  onsite?: boolean;
  hybrid?: boolean;
  locations?: string[];
  remoteScope?: string | null;
  visa?: boolean;
  intern?: boolean;
  salaryMin?: number | null;
  salaryMax?: number | null;
  salaryCurrency?: string | null;
  salaryPeriod?: string | null;
  equity?: boolean;
  applyUrl?: string | null;
  applyEmail?: string | null;
  tags?: string[];
}

const args = process.argv.slice(2);
const inIdx = args.indexOf("--in");
const inPath = inIdx !== -1 ? args[inIdx + 1] : "/tmp/parsed.json";

function locationDisplay(e: Extraction): string | null {
  const parts = [
    ...(e.locations ?? []),
    e.remote ? (e.remoteScope ? `Remote (${e.remoteScope})` : "Remote") : null,
  ].filter(Boolean);
  return parts.length > 0 ? parts.join(" / ") : null;
}

async function main() {
  const extractions: Extraction[] = JSON.parse(readFileSync(inPath, "utf8"));
  console.log(`Applying ${extractions.length} extraction(s) from ${inPath}…`);

  let applied = 0;
  let excluded = 0;

  for (const e of extractions) {
    if (e.exclude) {
      await prisma.job.update({
        where: { id: e.id },
        data: { hidden: true, hiddenReason: e.exclude, parseConfidence: "parsed" },
      });
      excluded++;
      continue;
    }

    const roles = e.roles ?? (e.role ? [e.role] : []);
    const tags = e.tags ?? [];
    const locations = e.locations ?? [];
    const rawText = ""; // taxonomy reads parsed fields primarily; raw kept upstream

    const taxonomy = classifyJobTaxonomy({
      role: e.role ?? null,
      roles,
      rawText,
      tags,
      employmentType: e.employmentType ?? null,
      parseConfidence: "parsed",
      intern: Boolean(e.intern),
      salaryMin: e.salaryMin ?? null,
      salaryMax: e.salaryMax ?? null,
      locationDisplay: locationDisplay(e),
      locations,
      remoteScope: e.remoteScope ?? null,
    });

    await prisma.job.update({
      where: { id: e.id },
      data: {
        company: e.company ?? null,
        role: e.role ?? null,
        roles: JSON.stringify(roles),
        employmentType: e.employmentType ?? null,
        remote: Boolean(e.remote),
        onsite: Boolean(e.onsite),
        hybrid: Boolean(e.hybrid),
        locations: JSON.stringify(locations),
        remoteScope: e.remoteScope ?? null,
        locationDisplay: locationDisplay(e),
        visa: Boolean(e.visa),
        intern: Boolean(e.intern),
        salaryMin: e.salaryMin ?? null,
        salaryMax: e.salaryMax ?? null,
        salaryCurrency: e.salaryCurrency ?? null,
        salaryPeriod: e.salaryPeriod ?? null,
        equity: Boolean(e.equity),
        applyUrl: e.applyUrl ?? null,
        applyEmail: e.applyEmail ?? null,
        tags: JSON.stringify(tags),
        parseConfidence: "parsed",
        ...serializeJobTaxonomy(taxonomy),
      },
    });
    applied++;
  }

  console.log(`Done. ${applied} extracted, ${excluded} excluded as non-postings.`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(() => process.exit(0));

