// Part 1 of the agent-driven backfill: dump a batch of low-confidence jobs to
// a JSON file for Claude (the agent) to extract structured fields from by hand.
//
// This is a ONE-TIME historical backfill mechanism. Ongoing ingest uses the
// heuristic parser + Gemini (npm run reparse:llm) — this harness is for the
// initial cleanup of the archive without burning API quota.
//
// Usage: npm run backfill:dump -- --limit 40 [--out /tmp/batch.json]

import { writeFileSync } from "node:fs";
import { prisma } from "@/lib/db";

const args = process.argv.slice(2);
const limitIdx = args.indexOf("--limit");
const limit = limitIdx !== -1 ? parseInt(args[limitIdx + 1], 10) : 40;
const outIdx = args.indexOf("--out");
const out = outIdx !== -1 ? args[outIdx + 1] : "/tmp/batch.json";

async function main() {
  const remaining = await prisma.job.count({
    where: { parseConfidence: { in: ["partial", "raw-only"] } },
  });

  const jobs = await prisma.job.findMany({
    where: { parseConfidence: { in: ["partial", "raw-only"] } },
    orderBy: { postedAt: "desc" },
    take: limit,
    select: { id: true, author: true, rawText: true, parseConfidence: true },
  });

  // Trim rawText so the batch file stays readable; the header + early body
  // carries the structured signal.
  const batch = jobs.map((j) => ({
    id: j.id,
    author: j.author,
    confidence: j.parseConfidence,
    text: j.rawText.slice(0, 1200),
  }));

  writeFileSync(out, JSON.stringify(batch, null, 2));
  console.log(
    `Wrote ${batch.length} job(s) to ${out}. ${remaining} low-confidence remaining total.`
  );
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(() => process.exit(0));

