// One-time noise sweep for the archive backfill. Auto-hides obvious non-job
// comments among the low-confidence rows so the hand-parse pass only deals with
// real postings. Conservative by design — only high-confidence junk signals.
//
// Runs in dry-run by default (counts + samples, no writes). Pass --apply to
// actually hide. Only touches rows where hidden is currently false.
//
// Usage:
//   npm run backfill:noise              # dry run
//   npm run backfill:noise -- --apply   # hide the matches

import { prisma } from "@/lib/db";

const apply = process.argv.includes("--apply");

type Reason = "flagged" | "empty" | "job-seeker" | "meta-noise";

// Classify a low-confidence comment as noise, or null if it looks like a real
// posting that needs a proper parse.
function noiseReason(rawText: string): Reason | null {
  const t = rawText.trim();
  const lower = t.toLowerCase();

  // HN moderation placeholders.
  if (/^\[(flagged|dead|deleted)\]$/i.test(t)) return "flagged";

  // Near-empty / gibberish: very short and no contact or link to act on.
  if (t.length < 25 && !/https?:\/\/|@/.test(t)) return "empty";

  // Meta-thread chatter — comments about the thread itself, not job posts.
  // These are high-precision patterns unlikely to match real postings.
  const metaPatterns = [
    /^@dang\b/i,
    /^please only post if /i,
    /^good luck finding/i,
    /^request to include /i,
    /^please everyone,? mention/i,
    /^(wow|ugh).*(seeking|international|financial|bold)/i,
    /^where can we sign up/i,
    /^what'?s up with all the (flagged|dead)/i,
    /^not(ice|icing).*pattern/i,
    /^213 comments/i,
    /^never hear anything from/i,
    /^i['']?ve applied.*haven['']?t heard/i,
    /^i would advise/i,
    /^be really careful/i,
    /^the ceo will not/i,
    /^with how many times/i,
    /^generic rejection/i,
    /^the wsj article/i,
    /^not gonna lie/i,
    /^i hate this/i,
    /^sent yet another/i,
    /^posted 30\+ days/i,
    /^if you're involved in marketing/i,
    /^hello!? i['']?ve actually applied/i,
    /^(estoy disponible|i['']?m available).*(cuando|whenever)/i,
    /^rem0te\b/i,
    /^wow a whopping/i,
    /^i['']?ve decided to no longer post/i,
    /^wouldn't recommend/i,
    /^applied (to this|half)/i,
    /^not hiring,? but/i,
    /^(i'm|i am) not sure if this is the right place/i,
    /^(kristina|hey kristina),? i sent you/i,
    /^very bad experience/i,
    /^(yogis?|yoga).*(pay attention|namaste)/i,
  ];
  if (metaPatterns.some((re) => re.test(t))) return "meta-noise";

  // "Who wants to be hired" seeker template. `Willing to relocate:` is the
  // strongest tell — hiring posts don't say it about themselves. Pair it with
  // another seeker marker to stay safe.
  const seekerMarkers = [
    /\bwilling to relocate\s*:/i,
    /\br[ée]sum[ée]\s*\/?\s*cv\s*:/i,
    /\bseeking\b.*\b(role|position|work|job)/i,
    /\bi['’]?m looking for\b.*\b(role|engineer|position|developer|work)/i,
  ];
  const hits = seekerMarkers.filter((re) => re.test(lower)).length;
  if (hits >= 2 || /\bwilling to relocate\s*:/i.test(lower)) return "job-seeker";

  return null;
}

async function main() {
  const jobs = await prisma.job.findMany({
    where: { parseConfidence: { in: ["partial", "raw-only"] }, hidden: false },
    select: { id: true, rawText: true },
  });

  const counts: Record<Reason, number> = { flagged: 0, empty: 0, "job-seeker": 0, "meta-noise": 0 };
  const samples: Record<Reason, string[]> = { flagged: [], empty: [], "job-seeker": [], "meta-noise": [] };
  const toHide: { id: number; reason: Reason }[] = [];

  for (const j of jobs) {
    const reason = noiseReason(j.rawText);
    if (!reason) continue;
    counts[reason]++;
    if (samples[reason].length < 3) {
      samples[reason].push(j.rawText.trim().slice(0, 90).replace(/\n/g, " "));
    }
    toHide.push({ id: j.id, reason });
  }

  console.log(`Scanned ${jobs.length} low-confidence visible rows.`);
  for (const r of ["flagged", "empty", "job-seeker", "meta-noise"] as Reason[]) {
    console.log(`\n${r}: ${counts[r]}`);
    for (const s of samples[r]) console.log(`   · ${s}`);
  }
  console.log(`\nTotal to hide: ${toHide.length}`);

  if (!apply) {
    console.log("\nDry run — no changes written. Re-run with --apply to hide.");
    return;
  }

  let done = 0;
  for (const { id, reason } of toHide) {
    await prisma.job.update({
      where: { id },
      data: { hidden: true, hiddenReason: reason, parseConfidence: "parsed" },
    });
    done++;
  }
  console.log(`\nHid ${done} noise row(s).`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(() => process.exit(0));

