// CLI LLM reparse: `npm run reparse:llm [--limit N]`
//
// Runs the LLM extraction pass on jobs where the heuristic parser produced
// `partial` or `raw-only` confidence. Skips jobs that already have
// parseConfidence === 'parsed' — those are fine as-is.
//
// Usage:
//   npm run reparse:llm            # all low-confidence jobs
//   npm run reparse:llm -- --limit 50   # first 50 (good for testing)

import { prisma } from "@/lib/db";
import { parseJob } from "@/lib/hn/parse";
import { llmParseJob } from "@/lib/hn/llm-parse";
import { classifyJobTaxonomy, serializeJobTaxonomy } from "@/lib/hn/taxonomy";

const args = process.argv.slice(2);
const limitIdx = args.indexOf("--limit");
const limit = limitIdx !== -1 ? parseInt(args[limitIdx + 1], 10) : undefined;

async function main() {
  const where = { parseConfidence: { in: ["partial", "raw-only"] } };

  const total = await prisma.job.count({ where });
  console.log(
    `Found ${total} low-confidence job(s). ${limit ? `Processing first ${limit}.` : "Processing all."}`
  );

  const jobs = await prisma.job.findMany({
    where,
    orderBy: { postedAt: "desc" },
    take: limit,
    select: {
      id: true,
      author: true,
      rawHtml: true,
      rawText: true,
      parseConfidence: true,
    },
  });

  let improved = 0;
  let failed = 0;
  let consecutiveFailures = 0;

  // Bail out if the API stops responding (e.g. daily quota exhausted) rather
  // than churning through thousands of jobs marking them failed. The run is
  // resumable — successful jobs are upgraded to `parsed` and skipped next time.
  const MAX_CONSECUTIVE_FAILURES = 8;

  for (let i = 0; i < jobs.length; i++) {
    const job = jobs[i];
    process.stdout.write(`[${i + 1}/${jobs.length}] job ${job.id} (${job.parseConfidence})… `);

    const heuristic = parseJob(job.rawText, job.rawHtml, { author: job.author });
    const result = await llmParseJob(job.rawText, heuristic);

    // Pace requests to stay under the free-tier limit (~10 req/min).
    await new Promise((r) => setTimeout(r, 6000));

    if (!result) {
      console.log("failed");
      failed++;
      consecutiveFailures++;
      if (consecutiveFailures >= MAX_CONSECUTIVE_FAILURES) {
        console.log(
          `\nAborting: ${MAX_CONSECUTIVE_FAILURES} consecutive failures (likely quota exhausted). Re-run to resume.`
        );
        break;
      }
      continue;
    }

    consecutiveFailures = 0;

    const taxonomy = classifyJobTaxonomy({
      role: result.role,
      roles: result.roles,
      rawText: job.rawText,
      tags: result.tags,
      employmentType: result.employmentType,
      parseConfidence: "parsed", // LLM pass upgrades confidence
      intern: result.intern,
      salaryMin: result.salaryMin,
      salaryMax: result.salaryMax,
      locationDisplay:
        [
          ...result.locations,
          result.remote
            ? result.remoteScope
              ? `Remote (${result.remoteScope})`
              : "Remote"
            : null,
        ]
          .filter(Boolean)
          .join(" / ") || null,
      locations: result.locations,
      remoteScope: result.remoteScope,
    });

    await prisma.job.update({
      where: { id: job.id },
      data: {
        company: result.company,
        role: result.role,
        roles: JSON.stringify(result.roles),
        employmentType: result.employmentType,
        remote: result.remote,
        onsite: result.onsite,
        hybrid: result.hybrid,
        locations: JSON.stringify(result.locations),
        remoteScope: result.remoteScope,
        locationDisplay:
          [
            ...result.locations,
            result.remote
              ? result.remoteScope
                ? `Remote (${result.remoteScope})`
                : "Remote"
              : null,
          ]
            .filter(Boolean)
            .join(" / ") || null,
        visa: result.visa,
        intern: result.intern,
        salaryMin: result.salaryMin,
        salaryMax: result.salaryMax,
        salaryCurrency: result.salaryCurrency,
        salaryPeriod: result.salaryPeriod,
        equity: result.equity,
        applyUrl: result.applyUrl,
        applyEmail: result.applyEmail,
        tags: JSON.stringify(result.tags),
        parseConfidence: "parsed",
        ...serializeJobTaxonomy(taxonomy),
      },
    });

    console.log(
      `ok → ${result.company ?? "(no company)"} | ${result.role ?? "(no role)"}`
    );
    improved++;
  }

  console.log(`\nDone. ${improved} improved, ${failed} failed.`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(() => process.exit(0));

