// CLI reparse: `npm run reparse`
// Refreshes derived parser/taxonomy/enrichment cache fields from stored raw HN
// snapshots. Does not mutate rawHtml/rawText or hidden moderation state.

import { prisma } from "@/lib/db";
import { deriveJobCache } from "@/lib/hn/derive";

async function main() {
  console.log("Reparsing stored raw HN snapshots…");
  const jobs = await prisma.job.findMany({
    orderBy: { postedAt: "desc" },
    select: { id: true, author: true, rawHtml: true, rawText: true },
  });

  let updated = 0;
  for (const job of jobs) {
    await prisma.job.update({
      where: { id: job.id },
      data: deriveJobCache(job.rawText, job.rawHtml, { author: job.author }),
    });
    updated++;
  }

  console.log(`Reparsed ${updated} job(s).`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exit(1);
  })
  .finally(() => process.exit(0));

