// Copy every Thread and Job from the live Postgres database into the local
// SQLite snapshot (prisma/snapshot.db). The snapshot is what production serves
// when SNAPSHOT_DB=1 — see lib/db.ts. Re-run any time the live data changes:
//
//   npm run db:snapshot
//
// Wipes and rewrites the snapshot, preserving row ids so /job/<id> URLs match.
import path from "path";
import { PrismaClient } from "@prisma/client";
import { PrismaClient as SnapshotClient } from "../lib/generated/snapshot";

const source = new PrismaClient();
const snapshot = new SnapshotClient({
  datasources: {
    db: { url: "file:" + path.join(__dirname, "..", "prisma", "snapshot.db") },
  },
});

const BATCH = 200;

async function main() {
  const threads = await source.thread.findMany({ orderBy: { id: "asc" } });
  const jobCount = await source.job.count();
  console.log(`source: ${threads.length} threads, ${jobCount} jobs`);

  await snapshot.job.deleteMany();
  await snapshot.thread.deleteMany();

  await snapshot.thread.createMany({ data: threads });

  let copied = 0;
  let cursor = 0;
  for (;;) {
    const jobs = await source.job.findMany({
      where: { id: { gt: cursor } },
      orderBy: { id: "asc" },
      take: BATCH,
    });
    if (jobs.length === 0) break;
    await snapshot.job.createMany({ data: jobs });
    cursor = jobs[jobs.length - 1].id;
    copied += jobs.length;
    process.stdout.write(`\rcopied ${copied}/${jobCount} jobs`);
  }
  console.log(`\nsnapshot complete: ${threads.length} threads, ${copied} jobs`);
}

main()
  .catch((e) => {
    console.error(e);
    process.exitCode = 1;
  })
  .finally(async () => {
    await source.$disconnect();
    await snapshot.$disconnect();
  });

